diffs.replacement:
{
  "name": "الزيارات الإشرافية للمجال الأول",
  "description": "منصة إلكترونية متكاملة لإدارة الزيارات الإشرافية والمشاريع التربوية للمجال الأول.",
  "requestFramePermissions": []
}

export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
  mustChangePassword?: boolean;
  isActive: boolean; // For soft delete
  joinedAt: string; // Year
  email?: string;
  phoneNumber?: string;
}

export interface ResetRequest {
  id: string;
  userId: string;
  userName: string;
  requestedAt: string;
  status: 'pending' | 'resolved';
}

export type AttachmentType = 'link' | 'image' | 'video' | 'audio' | 'file';

export interface Attachment {
  type: AttachmentType;
  url: string;
  name: string;
}

export interface Post {
  id: string;
  authorId: string;
  authorName: string;
  title: string;
  content: string;
  attachments: Attachment[];
  isPinned: boolean;
  createdAt: string;
  academicYear: string;
}

export interface ProjectSubmission {
  teacherId: string;
  files: Attachment[];
  notes: string;
  status: 'pending' | 'submitted' | 'approved' | 'needs_work';
  feedback: string;
  badges: string[]; // e.g., '🏆', '🌟', '💎'
  submittedAt?: string;
}

export interface Project {
  id: string;
  name: string;
  description: string; // Goals and description
  tasks: string[];
  assignedTeacherIds: string[]; // Access control
  createdAt: string;
  academicYear: string;
  submissions: Record<string, ProjectSubmission>; // teacherId -> Submission
}

// Legacy support for old data if needed, though we are pivoting to Project-based
export interface Lesson {
  id: string;
  teacherId: string;
  teacherName: string;
  title: string;
  strategiesCount: number;
  strategies: any[];
  selfLearningSkills: any;
  effectiveStrategiesDeployment: string;
  evaluationMethods: string;
  valuesAndCitizenship: string;
  createdAt: string;
  status?: 'pending' | 'confirmed';
  supervisorNotes?: string;
  observationalNotes?: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson, Project, Post, ResetRequest } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const CURRENT_ACADEMIC_YEAR = "2025-2026";
const APP_TITLE = "الزيارات الإشرافية للمجال الأول";

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('app_projects');
    return saved ? JSON.parse(saved) : [];
  });

  const [posts, setPosts] = useState<Post[]>(() => {
    const saved = localStorage.getItem('app_posts');
    return saved ? JSON.parse(saved) : [];
  });

  const [resetRequests, setResetRequests] = useState<ResetRequest[]>(() => {
    const saved = localStorage.getItem('app_reset_requests');
    return saved ? JSON.parse(saved) : [];
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  useEffect(() => {
    localStorage.setItem('app_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem('app_posts', JSON.stringify(posts));
  }, [posts]);

  useEffect(() => {
    localStorage.setItem('app_reset_requests', JSON.stringify(resetRequests));
  }, [resetRequests]);

  const handleLogin = (user: User) => {
    if (!user.isActive) {
      alert('عذراً، هذا الحساب غير نشط. يرجى مراجعة إدارة المنصة.');
      return;
    }
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(true);
    } else {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  // User Management
  const handleAddTeacher = (id: string, name: string, email?: string, phoneNumber?: string) => {
    const exists = teachers.find(t => t.id === id);
    const defaultPassword = `OM${id}`;

    if (exists) {
      if (!exists.isActive) {
        if (window.confirm('هذا الحساب موجود ولكنه معطل (مؤرشف). هل تريد إعادة تفعيله؟')) {
          setTeachers(prev => prev.map(t => t.id === id ? { 
            ...t, 
            isActive: true, 
            mustChangePassword: true, 
            password: defaultPassword,
            email: email || t.email,
            phoneNumber: phoneNumber || t.phoneNumber
          } : t));
        }
        return;
      }
      return alert('هذا الرقم الوظيفي موجود مسبقاً');
    }

    const newTeacher: User = {
      id,
      code: id,
      name,
      role: UserRole.TEACHER,
      password: defaultPassword,
      mustChangePassword: true,
      isActive: true,
      joinedAt: CURRENT_ACADEMIC_YEAR,
      email,
      phoneNumber
    };
    setTeachers(prev => [...prev, newTeacher]);
  };

  const handleSoftDeleteTeacher = (teacherId: string) => {
    if (window.confirm('هل أنت متأكد من أرشفة حساب المعلمة؟ سيتم تعطيل الدخول ولكن ستبقى البيانات محفوظة في الأرشيف.')) {
      setTeachers(prev => prev.map(t => t.id === teacherId ? { ...t, isActive: false } : t));
    }
  };

  const handleResetTeacherPassword = (teacherId: string) => {
    const defaultPass = `OM${teacherId}`;
    setTeachers(prev => prev.map(t => 
      t.id === teacherId ? { ...t, password: defaultPass, mustChangePassword: true } : t
    ));
    // Also resolve any pending reset request
    setResetRequests(prev => prev.map(req => req.userId === teacherId ? { ...req, status: 'resolved' } : req));
    return defaultPass;
  };

  // Forgot Password Management
  const handleForgotPassword = (userId: string) => {
    // Check if it's a supervisor (S... or 99...)
    const isSupervisor = userId.toUpperCase().startsWith('S') || userId.startsWith('99');

    if (isSupervisor) {
      // Supervisor logic: prompt for unified password
      alert('عزيزتي المشرفة، يرجى كتابة كلمة المرور الموحدة (التي تم تسليمها لك عند استلام النظام) أو كلمة المرور السابقة الخاصة بك.');
      return 'supervisor';
    }

    const teacher = teachers.find(t => t.id === userId && t.isActive);
    if (!teacher) {
      alert('الرقم الوظيفي غير موجود أو الحساب معطل.');
      return 'not_found';
    }

    // Teacher logic: Send request to supervisor
    const newRequest: ResetRequest = {
      id: Date.now().toString(),
      userId: teacher.id,
      userName: teacher.name,
      requestedAt: new Date().toLocaleString('ar-SA'),
      status: 'pending'
    };

    // Avoid duplicates
    setResetRequests(prev => {
      if (prev.find(r => r.userId === userId && r.status === 'pending')) return prev;
      return [newRequest, ...prev];
    });

    alert('تم إرسال طلب تصفير كلمة المرور للمشرفة بنجاح. يرجى الانتظار حتى تقوم المشرفة بإعادة تعيين حسابك.');
    return 'teacher_requested';
  };

  // Posts Management
  const handleAddPost = (post: Post) => {
    setPosts(prev => [post, ...prev]);
  };

  const handleDeletePost = (postId: string) => {
    if (window.confirm('حذف هذا المنشور؟')) {
      setPosts(prev => prev.filter(p => p.id !== postId));
    }
  };

  const handleTogglePinPost = (postId: string) => {
    setPosts(prev => prev.map(p => p.id === postId ? { ...p, isPinned: !p.isPinned } : p));
  };

  // Projects Management
  const handleAddProject = (project: Project) => {
    setProjects(prev => [project, ...prev]);
  };

  const handleDeleteProject = (projectId: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا المشروع نهائياً؟')) {
      setProjects(prev => prev.filter(p => p.id !== projectId));
    }
  };

  const handleUpdateProjectSubmission = (projectId: string, submission: any) => {
    setProjects(prev => prev.map(p => {
      if (p.id === projectId) {
        return {
          ...p,
          submissions: {
            ...p.submissions,
            [submission.teacherId]: submission
          }
        };
      }
      return p;
    }));
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false, password: newPassword } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} teachers={teachers} onForgotPassword={handleForgotPassword} />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm 
      onPasswordChanged={handlePasswordChanged} 
      onLogout={handleLogout} 
      currentPassword={auth.user?.password}
    />;
  }

  return (
    <div className="min-h-screen bg-[#f8fafc] font-['Tajawal'] antialiased">
      <nav className="bg-white/90 backdrop-blur-md text-slate-900 shadow-sm sticky top-0 z-[100] border-b border-slate-100 h-20 flex items-center">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="bg-gradient-to-tr from-emerald-600 to-teal-600 p-2.5 rounded-2xl shadow-lg shadow-emerald-100">
                <span className="text-2xl">📋</span>
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black tracking-tight text-slate-900 leading-none mb-1">{APP_TITLE}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">المجال الأول - العام الدراسي {CURRENT_ACADEMIC_YEAR}</span>
              </div>
            </div>
            <div className="flex items-center gap-4 md:gap-6">
              <div className="hidden md:flex flex-col items-end">
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
                <span className="text-[10px] font-bold text-emerald-500 uppercase">{auth.user?.role === UserRole.SUPERVISOR ? 'مشرفة النظام' : 'عضو هيئة التدريس'}</span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-slate-50 text-slate-600 hover:bg-red-50 hover:text-red-600 px-5 py-2.5 rounded-xl text-xs font-black transition-all active:scale-95 border border-slate-100"
              >
                تسجيل الخروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            posts={posts}
            projects={projects}
            updateProjectSubmission={handleUpdateProjectSubmission}
          />
        ) : (
          <SupervisorDashboard 
            teachers={teachers}
            posts={posts}
            projects={projects}
            resetRequests={resetRequests}
            onAddPost={handleAddPost}
            onDeletePost={handleDeletePost}
            onTogglePinPost={handleTogglePinPost}
            onAddTeacher={handleAddTeacher}
            onSoftDeleteTeacher={handleSoftDeleteTeacher}
            onResetPassword={handleResetTeacherPassword}
            onAddProject={handleAddProject}
            onDeleteProject={handleDeleteProject}
            onUpdateProjectSubmission={handleUpdateProjectSubmission}
            academicYear={CURRENT_ACADEMIC_YEAR}
          />
        )}
      </main>

      <footer className="py-8 text-center text-slate-400 text-[10px] font-bold border-t border-slate-100 mt-12 bg-white/50">
        جميع الحقوق محفوظة - {APP_TITLE} © {CURRENT_ACADEMIC_YEAR}
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  teachers: User[];
  onForgotPassword: (userId: string) => void;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, teachers, onForgotPassword }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [showForgotModal, setShowForgotModal] = useState(false);
  const [forgotId, setForgotId] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال الرقم الوظيفي وكلمة المرور');
      return;
    }

    // Supervisor Login Check
    const isSupervisor = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99');

    if (isSupervisor) {
      const isValidSupervisor = 
        (cleanCode.toUpperCase() === 'S12345' && cleanPass === 'OM12345') || 
        (cleanPass === `${cleanCode}مشرف`);

      if (isValidSupervisor) {
        onLogin({ 
          id: cleanCode, 
          name: `المشرفة (${cleanCode})`, 
          role: UserRole.SUPERVISOR, 
          code: cleanCode,
          isActive: true,
          joinedAt: '2026'
        });
        return;
      } else {
        setError('كلمة مرور المشرفة غير صحيحة');
        return;
      }
    }

    // Teacher check
    const teacher = teachers.find(t => t.id === cleanCode);
    if (!teacher) {
      setError('المعلمة غير مسجلة في النظام');
      return;
    }

    if (cleanPass === teacher.password) {
      onLogin(teacher);
    } else {
      setError('كلمة المرور غير صحيحة');
    }
  };

  const handleForgotSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (forgotId.trim()) {
      onForgotPassword(forgotId.trim());
      setShowForgotModal(false);
      setForgotId('');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#f8fafc] px-4 font-['Tajawal'] bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
      <div className="max-w-md w-full bg-white/90 backdrop-blur-xl rounded-[2.5rem] shadow-2xl p-10 space-y-8 border border-white relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-emerald-500 via-teal-500 to-blue-500"></div>
        <div className="text-center">
          <div className="mb-6 inline-flex items-center justify-center w-24 h-24 bg-gradient-to-br from-emerald-50 to-teal-50 rounded-[2rem] shadow-inner relative">
             <span className="text-5xl absolute top-4 right-4">📋</span>
             <span className="text-4xl absolute bottom-4 left-4">✒️</span>
          </div>
          <h1 className="text-2xl font-black text-slate-800 mb-2 tracking-tight">الزيارات الإشرافية للمجال الأول</h1>
          <p className="text-slate-500 font-bold text-sm">بوابة الدخول الموحدة للمجال الأول</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 pr-2">الرقم الوظيفي</label>
            <input type="text" required value={code} onChange={(e) => setCode(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-emerald-500 outline-none text-right font-extrabold text-lg transition-all focus:bg-white text-slate-900 placeholder:text-slate-400" placeholder="أدخل الرقم الوظيفي..." />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 pr-2">كلمة المرور</label>
            <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-emerald-500 outline-none text-right font-extrabold text-lg transition-all focus:bg-white text-slate-900 placeholder:text-slate-400" placeholder="••••••••" />
          </div>

          {error && <div className="bg-red-50 text-red-600 text-xs font-black p-4 rounded-2xl text-center animate-pulse">{error}</div>}

          <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg hover:bg-emerald-600 shadow-xl shadow-emerald-100 active:scale-95 transition-all mt-4">تسجيل الدخول</button>
        </form>

        <div className="text-center pt-2">
           <button 
             onClick={() => setShowForgotModal(true)} 
             className="text-xs font-bold text-slate-400 hover:text-emerald-600 transition-colors underline decoration-dotted underline-offset-4"
           >
             نسيت كلمة المرور؟
           </button>
        </div>

        <div className="text-center text-[10px] text-slate-300 font-bold pt-4 border-t border-slate-50">
          الزيارات الإشرافية للمجال الأول © 2026
        </div>
      </div>

      {/* Forgot Password Modal */}
      {showForgotModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 shadow-2xl animate-slideIn">
              <h3 className="text-xl font-black text-slate-800 mb-2">نسيت كلمة المرور؟</h3>
              <p className="text-slate-500 text-xs font-bold mb-6 leading-relaxed">يرجى إدخال الرقم الوظيفي الخاص بك لإعادة تعيين الحساب.</p>

              <form onSubmit={handleForgotSubmit} className="space-y-4">
                 <input 
                   type="text" 
                   required 
                   placeholder="أدخل الرقم الوظيفي هنا" 
                   value={forgotId}
                   onChange={e => setForgotId(e.target.value)}
                   className="w-full px-5 py-3 rounded-xl bg-slate-50 border border-slate-100 outline-none focus:border-emerald-500 font-black text-lg text-center"
                 />
                 <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-black text-sm shadow-lg hover:bg-emerald-700 transition-all">إرسال الطلب</button>
                 <button type="button" onClick={() => setShowForgotModal(false)} className="w-full text-slate-400 font-bold text-xs py-2">إلغاء</button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default LoginForm;

import React, { useState, useMemo } from 'react';
import { User, Project, Post, ProjectSubmission, Attachment, ResetRequest } from '../types';

interface SupervisorDashboardProps {
  teachers: User[];
  posts: Post[];
  projects: Project[];
  resetRequests: ResetRequest[];
  onAddPost: (post: Post) => void;
  onDeletePost: (id: string) => void;
  onTogglePinPost: (id: string) => void;
  onAddTeacher: (id: string, name: string, email?: string, phone?: string) => void;
  onSoftDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (project: Project) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
  academicYear: string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  teachers, posts, projects, resetRequests,
  onAddPost, onDeletePost, onTogglePinPost,
  onAddTeacher, onSoftDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateProjectSubmission,
  academicYear
}) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'projects' | 'teachers' | 'archive'>('feed');

  // Post Form State
  const [postContent, setPostContent] = useState('');
  const [postTitle, setPostTitle] = useState('');
  const [postAttachments, setPostAttachments] = useState<Attachment[]>([]);
  const [isPostPinned, setIsPostPinned] = useState(false);

  // Project Form State
  const [newProjectName, setNewProjectName] = useState('');
  const [newProjectGoals, setNewProjectGoals] = useState('');
  const [newProjectTasks, setNewProjectTasks] = useState('');
  const [selectedTeachers, setSelectedTeachers] = useState<string[]>([]);
  const [showProjectForm, setShowProjectForm] = useState(false);

  // Teacher Form State
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [newTeacherEmail, setNewTeacherEmail] = useState('');
  const [newTeacherPhone, setNewTeacherPhone] = useState('');
  const [showTeacherForm, setShowTeacherForm] = useState(false);

  // Selected Project for Review
  const [selectedReviewProjectId, setSelectedReviewProjectId] = useState<string | null>(null);

  // Temporary feedback state (local edits before save)
  const [feedbackText, setFeedbackText] = useState<Record<string, string>>({});

  // Archive Filter
  const [archiveYear, setArchiveYear] = useState(academicYear);

  const activeTeachers = useMemo(() => teachers.filter(t => t.isActive), [teachers]);
  const archivedTeachers = useMemo(() => teachers.filter(t => !t.isActive), [teachers]);

  const pendingResets = useMemo(() => resetRequests.filter(r => r.status === 'pending'), [resetRequests]);

  const filteredArchiveData = useMemo(() => {
    return {
      teachers: archivedTeachers,
      projects: projects.filter(p => p.academicYear === archiveYear)
    };
  }, [archivedTeachers, projects, archiveYear]);

  // Handlers
  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!postTitle || !postContent) return alert('يرجى كتابة العنوان والمحتوى');

    const newPost: Post = {
      id: Date.now().toString(),
      authorId: 'supervisor',
      authorName: 'الإدارة المدرسية',
      title: postTitle,
      content: postContent,
      attachments: postAttachments,
      isPinned: isPostPinned,
      createdAt: new Date().toLocaleDateString('ar-SA'),
      academicYear
    };
    onAddPost(newPost);
    setPostTitle('');
    setPostContent('');
    setPostAttachments([]);
    setIsPostPinned(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = () => {
        setPostAttachments(prev => [...prev, {
          type: file.type.startsWith('image') ? 'image' : 'file',
          url: reader.result as string,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateProject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProjectName) return;

    const tasks = newProjectTasks.split('\n').filter(t => t.trim());

    const newProject: Project = {
      id: Date.now().toString(),
      name: newProjectName,
      description: newProjectGoals,
      tasks: tasks,
      assignedTeacherIds: selectedTeachers.length > 0 ? selectedTeachers : activeTeachers.map(t => t.id),
      createdAt: new Date().toLocaleDateString('ar-SA'),
      academicYear,
      submissions: {}
    };
    onAddProject(newProject);
    setNewProjectName('');
    setNewProjectGoals('');
    setNewProjectTasks('');
    setSelectedTeachers([]);
    setShowProjectForm(false);
  };

  const handleAwardBadge = (projectId: string, teacherId: string, badge: string) => {
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const submission = project.submissions[teacherId] || { 
      teacherId, files: [], notes: '', status: 'pending', feedback: '', badges: [] 
    };

    const newBadges = submission.badges.includes(badge) ? submission.badges : [...submission.badges, badge];
    onUpdateProjectSubmission(projectId, { ...submission, badges: newBadges });
  };

  const handleApproveSubmission = (projectId: string, teacherId: string) => {
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const submission = project.submissions[teacherId];
    if (submission) {
      onUpdateProjectSubmission(projectId, { ...submission, status: 'approved' });
    }
  };

  const handleSaveFeedback = (projectId: string, teacherId: string) => {
    const text = feedbackText[teacherId];
    if (text === undefined) return;

    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const submission = project.submissions[teacherId];
    if (submission) {
      onUpdateProjectSubmission(projectId, { ...submission, feedback: text });
      alert('تم إرسال الملاحظات للمعلمة بنجاح');
      setFeedbackText(prev => {
        const next = {...prev};
        delete next[teacherId];
        return next;
      });
    }
  };

  const handleCreateTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTeacherId && newTeacherName) {
      onAddTeacher(newTeacherId, newTeacherName, newTeacherEmail, newTeacherPhone);
      setNewTeacherId('');
      setNewTeacherName('');
      setNewTeacherEmail('');
      setNewTeacherPhone('');
      setShowTeacherForm(false);
    }
  };

  const handleResetTeacher = (id: string, name: string) => {
    if (window.confirm(`هل أنت متأكد من إعادة تعيين كلمة المرور للمعلمة ${name}؟ ستعود إلى OM${id}`)) {
      onResetPassword(id);
      alert('تم إعادة تعيين كلمة المرور بنجاح');
    }
  };

  const getFileIcon = (type: string, name: string) => {
    if (type === 'link') return '🔗';
    if (type === 'video') return '🎥';
    if (type === 'audio') return '🎙️';
    if (type === 'image') return '🖼️';

    const lowerName = name.toLowerCase();
    if (lowerName.endsWith('.pdf')) return '📕';
    if (lowerName.endsWith('.ppt') || lowerName.endsWith('.pptx')) return '📊';
    if (lowerName.endsWith('.doc') || lowerName.endsWith('.docx')) return '📝';
    if (lowerName.endsWith('.xls') || lowerName.endsWith('.xlsx')) return '📈';

    return '📄';
  };

  return (
    <div className="space-y-8 pb-20 animate-fadeIn">
      {/* Reset Requests Banner */}
      {pendingResets.length > 0 && (
        <div className="bg-amber-100 border-r-4 border-amber-500 p-6 rounded-2xl shadow-md animate-bounce-subtle">
           <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                 <span className="text-2xl">🔔</span>
                 <div>
                    <h4 className="font-black text-amber-900 text-sm">لديكِ {pendingResets.length} طلبات إعادة تعيين كلمة المرور</h4>
                    <p className="text-amber-800 text-[10px] font-bold">يرجى معالجة طلبات المعلمات لتمكينهن من الدخول.</p>
                 </div>
              </div>
              <button 
                onClick={() => setActiveTab('teachers')} 
                className="bg-amber-600 text-white px-4 py-2 rounded-xl text-[10px] font-black hover:bg-amber-700 transition-all"
              >
                عرض الطلبات
              </button>
           </div>
        </div>
      )}

      {/* Navigation Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-3xl overflow-x-auto">
          {[
            { id: 'feed', label: '📢 مركز التواصل', color: 'emerald' },
            { id: 'projects', label: '🚀 إدارة المشاريع', color: 'teal' },
            { id: 'teachers', label: '👥 المعلمات', color: 'indigo' },
            { id: 'archive', label: '📂 الأرشيف', color: 'amber' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as any); setSelectedReviewProjectId(null); }}
              className={`flex-1 min-w-[100px] px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                activeTab === tab.id 
                  ? `bg-emerald-600 text-white shadow-lg` 
                  : `text-slate-500 hover:bg-emerald-50`
              }`}
            >
              {tab.label}
              {tab.id === 'teachers' && pendingResets.length > 0 && (
                <span className="bg-red-500 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center animate-pulse">!</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {/* FEED TAB */}
      {activeTab === 'feed' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1">
             <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 sticky top-24">
                <h3 className="text-xl font-black text-slate-800 mb-6 flex items-center gap-2">
                  <span>✍️</span> إنشاء تعميم جديد
                </h3>
                <form onSubmit={handleCreatePost} className="space-y-4">
                  <input 
                    type="text" 
                    placeholder="عنوان التعميم" 
                    value={postTitle}
                    onChange={e => setPostTitle(e.target.value)}
                    className="w-full px-5 py-3 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-emerald-500 outline-none font-bold text-sm text-slate-900"
                  />
                  <textarea 
                    placeholder="نص التعميم..." 
                    value={postContent}
                    onChange={e => setPostContent(e.target.value)}
                    className="w-full px-5 py-3 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-emerald-500 outline-none font-bold text-sm text-slate-900 min-h-[120px]"
                  />

                  <div className="flex items-center gap-2">
                     <label className="flex-1 cursor-pointer bg-slate-50 hover:bg-slate-100 px-4 py-3 rounded-xl border border-dashed border-slate-300 text-slate-500 text-xs font-black flex items-center justify-center gap-2 transition-all">
                        <span>📎 إرفاق ملف</span>
                        <input type="file" onChange={handleFileUpload} className="hidden" />
                     </label>
                     <label className={`cursor-pointer px-4 py-3 rounded-xl border-2 text-xs font-black transition-all ${isPostPinned ? 'bg-amber-50 border-amber-400 text-amber-600' : 'bg-white border-slate-100 text-slate-400'}`}>
                        📌 تثبيت
                        <input type="checkbox" checked={isPostPinned} onChange={e => setIsPostPinned(e.target.checked)} className="hidden" />
                     </label>
                  </div>

                  {postAttachments.length > 0 && (
                    <div className="flex gap-2 flex-wrap">
                      {postAttachments.map((att, i) => (
                        <div key={i} className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-lg text-[10px] font-bold truncate max-w-[150px]">
                          {att.name}
                        </div>
                      ))}
                    </div>
                  )}

                  <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition-all">نشر التعميم</button>
                </form>
             </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
             <h3 className="text-xl font-black text-slate-800 pr-2">📝 آخر المستجدات</h3>
             {posts.length === 0 ? (
               <div className="text-center py-20 bg-white rounded-[2.5rem] border-2 border-dashed border-slate-100 text-slate-300 font-bold">لا توجد تعاميم منشورة</div>
             ) : (
               posts.sort((a, b) => (a.isPinned === b.isPinned ? 0 : a.isPinned ? -1 : 1)).map(post => (
                 <div key={post.id} className={`bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 relative group transition-all hover:shadow-md ${post.isPinned ? 'border-r-8 border-r-amber-400' : ''}`}>
                    <div className="flex justify-between items-start mb-4">
                       <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-lg">🏫</div>
                          <div>
                            <h4 className="font-black text-slate-900">{post.title}</h4>
                            <span className="text-[10px] text-slate-400 font-bold">{post.createdAt}</span>
                          </div>
                       </div>
                       <div className="flex gap-2">
                         <button onClick={() => onTogglePinPost(post.id)} className={`text-xl ${post.isPinned ? 'grayscale-0' : 'grayscale opacity-20'}`}>📌</button>
                         <button onClick={() => onDeletePost(post.id)} className="text-slate-200 hover:text-red-500 font-bold px-2">✕</button>
                       </div>
                    </div>
                    <p className="text-slate-600 font-bold text-sm leading-relaxed whitespace-pre-line mb-6">{post.content}</p>
                    {post.attachments.length > 0 && (
                      <div className="flex gap-3 overflow-x-auto pb-2">
                        {post.attachments.map((att, i) => (
                          <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-xl border border-slate-100 text-xs font-black text-emerald-600 hover:bg-emerald-50 transition-colors">
                            {getFileIcon(att.type, att.name)} {att.name}
                          </a>
                        ))}
                      </div>
                    )}
                 </div>
               ))
             )}
          </div>
        </div>
      )}

      {/* PROJECTS TAB */}
      {activeTab === 'projects' && (
        <div className="space-y-8 animate-fadeIn">
          {!selectedReviewProjectId ? (
            <>
               <div className="flex justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
                  <div>
                    <h3 className="text-2xl font-black text-slate-900">المشاريع التربوية</h3>
                    <p className="text-slate-400 font-bold text-sm">التخطيط والمتابعة للإنجازات</p>
                  </div>
                  <button onClick={() => setShowProjectForm(!showProjectForm)} className="bg-teal-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-teal-700 transition-all">
                    {showProjectForm ? 'إلغاء' : '+ مشروع جديد'}
                  </button>
               </div>

               {showProjectForm && (
                 <div className="bg-white p-10 rounded-[3rem] shadow-xl border-4 border-teal-50 animate-slideDown">
                    <form onSubmit={handleCreateProject} className="space-y-6">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                         <input type="text" placeholder="اسم المشروع" value={newProjectName} onChange={e => setNewProjectName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 font-bold focus:bg-white border-2 border-slate-50 focus:border-teal-400 outline-none text-slate-900" />
                         <input type="text" placeholder="الأهداف العامة" value={newProjectGoals} onChange={e => setNewProjectGoals(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 font-bold focus:bg-white border-2 border-slate-50 focus:border-teal-400 outline-none text-slate-900" />
                      </div>
                      <textarea placeholder="المهام المطلوبة (كل مهمة في سطر)" value={newProjectTasks} onChange={e => setNewProjectTasks(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 font-bold focus:bg-white border-2 border-slate-50 focus:border-teal-400 outline-none min-h-[100px] text-slate-900" />

                      <div>
                        <label className="block text-sm font-black text-slate-500 mb-3">إسناد المهام إلى:</label>
                        <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-4 bg-slate-50 rounded-2xl border border-slate-100">
                           <button type="button" onClick={() => setSelectedTeachers([])} className={`px-4 py-2 rounded-xl text-xs font-black ${selectedTeachers.length === 0 ? 'bg-teal-600 text-white' : 'bg-white text-slate-500'}`}>الجميع</button>
                           {activeTeachers.map(t => (
                             <button 
                               key={t.id} 
                               type="button"
                               onClick={() => {
                                 setSelectedTeachers(prev => prev.includes(t.id) ? prev.filter(id => id !== t.id) : [...prev, t.id]);
                               }}
                               className={`px-4 py-2 rounded-xl text-xs font-black border transition-all ${selectedTeachers.includes(t.id) ? 'bg-teal-100 border-teal-300 text-teal-700' : 'bg-white border-slate-100 text-slate-500'}`}
                             >
                               {t.name}
                             </button>
                           ))}
                        </div>
                      </div>

                      <button type="submit" className="w-full bg-teal-600 text-white py-4 rounded-2xl font-black shadow-lg">إطلاق المشروع 🚀</button>
                    </form>
                 </div>
               )}

               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {projects.map(project => (
                   <div key={project.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col hover:shadow-xl transition-all group">
                      <div className="flex justify-between items-start mb-4">
                        <span className="bg-teal-50 text-teal-600 px-3 py-1 rounded-lg text-[10px] font-black">مشروع نشط</span>
                        <button onClick={() => onDeleteProject(project.id)} className="text-slate-300 hover:text-red-500">🗑️</button>
                      </div>
                      <h3 className="text-xl font-black text-slate-800 mb-2">{project.name}</h3>
                      <p className="text-slate-400 text-xs font-bold line-clamp-2 mb-6">{project.description}</p>

                      <div className="mt-auto border-t border-slate-50 pt-4 flex justify-between items-center">
                         <div className="flex -space-x-2 rtl:space-x-reverse">
                           {project.assignedTeacherIds.slice(0, 4).map((tid, idx) => (
                             <div key={idx} className="w-8 h-8 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-[8px] font-black text-slate-500">
                               {teachers.find(t => t.id === tid)?.name.charAt(0)}
                             </div>
                           ))}
                           {project.assignedTeacherIds.length > 4 && <div className="w-8 h-8 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-[8px] font-black text-slate-500">+{project.assignedTeacherIds.length - 4}</div>}
                         </div>
                         <button onClick={() => setSelectedReviewProjectId(project.id)} className="bg-slate-900 text-white px-5 py-2 rounded-xl text-xs font-black hover:bg-teal-600 transition-colors">متابعة الإنجاز</button>
                      </div>
                   </div>
                 ))}
               </div>
            </>
          ) : (
            <div className="bg-white rounded-[3rem] shadow-xl p-10 min-h-[600px] animate-slideUp">
               {(() => {
                 const project = projects.find(p => p.id === selectedReviewProjectId);
                 if (!project) return null;

                 const targetTeachers = project.assignedTeacherIds.map(id => teachers.find(t => t.id === id)).filter(Boolean) as User[];

                 return (
                   <div className="space-y-8">
                     <div className="flex items-center justify-between border-b border-slate-100 pb-6">
                        <div className="flex items-center gap-4">
                           <button onClick={() => setSelectedReviewProjectId(null)} className="bg-slate-100 hover:bg-slate-200 px-4 py-2 rounded-xl font-bold text-slate-600 transition">عودة</button>
                           <div>
                             <h2 className="text-2xl font-black text-slate-900">{project.name}</h2>
                             <p className="text-slate-400 text-xs font-bold mt-1">قائمة المهام: {project.tasks.join(' • ')}</p>
                           </div>
                        </div>
                        <div className="text-xs font-black text-teal-600 bg-teal-50 px-4 py-2 rounded-xl">السنة الدراسية: {project.academicYear}</div>
                     </div>

                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {targetTeachers.map(teacher => {
                          const submission = project.submissions[teacher.id];
                          return (
                            <div key={teacher.id} className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 flex flex-col">
                               <div className="flex justify-between items-center mb-4">
                                  <h4 className="font-black text-slate-800">{teacher.name}</h4>
                                  <span className={`text-[10px] font-black px-3 py-1 rounded-full ${submission ? (submission.status === 'approved' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600') : 'bg-slate-200 text-slate-500'}`}>
                                    {submission ? (submission.status === 'approved' ? 'معتمد' : 'قيد المراجعة') : 'لم يسلم بعد'}
                                  </span>
                               </div>

                               {submission ? (
                                 <div className="space-y-3 flex-1 flex flex-col">
                                   {submission.notes && (
                                     <div className="bg-white p-3 rounded-xl text-xs font-bold text-slate-600 border border-slate-100">
                                       {submission.notes}
                                     </div>
                                   )}
                                   {submission.files.length > 0 && (
                                     <div className="flex flex-wrap gap-2">
                                       {submission.files.map((f, i) => (
                                         <a key={i} href={f.url} target={f.type === 'link' ? '_blank' : '_self'} download={f.type !== 'link' ? f.name : undefined} className="flex items-center gap-1 bg-white px-3 py-2 rounded-lg text-[10px] font-black text-indigo-600 border border-slate-100 hover:bg-indigo-50">
                                            {getFileIcon(f.type, f.name)} {f.name}
                                         </a>
                                       ))}
                                     </div>
                                   )}

                                   <div className="pt-4 mt-auto border-t border-slate-200 space-y-3">
                                      <div className="bg-white p-2 rounded-xl border border-slate-100">
                                        <textarea
                                          className="w-full text-[10px] font-bold text-slate-600 outline-none resize-none bg-transparent"
                                          placeholder="إرسال ملاحظات أو روابط للمعلمة..."
                                          rows={2}
                                          value={feedbackText[teacher.id] ?? (submission.feedback || '')}
                                          onChange={(e) => setFeedbackText(prev => ({...prev, [teacher.id]: e.target.value}))}
                                        />
                                        <div className="flex justify-end mt-1">
                                          <button 
                                            onClick={() => handleSaveFeedback(project.id, teacher.id)}
                                            className="bg-slate-100 text-slate-500 hover:bg-indigo-50 hover:text-indigo-600 px-3 py-1 rounded-lg text-[9px] font-black transition-colors"
                                          >
                                            إرسال الملاحظات 📤
                                          </button>
                                        </div>
                                      </div>

                                      <div className="flex flex-wrap gap-2 justify-center pt-2">
                                        {submission.status !== 'approved' && (
                                          <button onClick={() => handleApproveSubmission(project.id, teacher.id)} className="bg-emerald-500 text-white px-4 py-2 rounded-lg text-xs font-black hover:bg-emerald-600 w-full">اعتماد ✅</button>
                                        )}
                                        <div className="flex gap-1 justify-center w-full">
                                           {['🏆', '🌟', '💎', '💡'].map(badge => (
                                             <button 
                                               key={badge} 
                                               onClick={() => handleAwardBadge(project.id, teacher.id, badge)}
                                               className={`w-8 h-8 rounded-full border bg-white hover:bg-slate-50 flex items-center justify-center text-lg ${submission.badges?.includes(badge) ? 'border-amber-400 bg-amber-50' : 'border-slate-100'}`}
                                             >
                                               {badge}
                                             </button>
                                           ))}
                                        </div>
                                      </div>
                                   </div>
                                 </div>
                               ) : (
                                 <div className="text-center py-6 text-slate-300 font-bold text-xs">لا يوجد إنجاز</div>
                               )}
                            </div>
                          );
                        })}
                     </div>
                   </div>
                 );
               })()}
            </div>
          )}
        </div>
      )}

      {/* TEACHERS TAB */}
      {activeTab === 'teachers' && (
