                             <div className="text-[10px] text-slate-500 font-bold">بتاريخ: {req.requestedAt}</div>
                          </div>
                          <button 
                            onClick={() => handleResetTeacher(req.userId, req.userName)}
                            className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-[10px] font-black shadow-sm"
