                   <div className="border-t border-slate-100 pt-6 space-y-4">
                      <h5 className="font-black text-slate-700 text-sm">التواصل مع المشرفة ({material.comments.length}):</h5>
                      <div className="space-y-3">
                         {material.comments.map(c => (
                           <div key={c.id} className={`p-4 rounded-2xl text-sm ${c.authorRole === UserRole.TEACHER ? 'bg-indigo-50 mr-8' : 'bg-emerald-50 ml-8 border-r-4 border-emerald-400'}`}>
                              <div className="flex justify-between mb-1">
                                 <span className="font-black text-slate-800">{c.authorName}</span>
                                 <span className="text-[10px] text-slate-400">{c.createdAt}</span>
