import React, { useState, useMemo } from 'react';
import { User, Project, Post, ProjectSubmission, Attachment, ResetRequest, LessonMaterial, Comment, UserRole } from '../types';

interface SupervisorDashboardProps {
  user: User;
  teachers: User[];
  posts: Post[];
  projects: Project[];
  lessonMaterials: LessonMaterial[];
  resetRequests: ResetRequest[];
  onAddPost: (post: Post) => void;
  onDeletePost: (id: string) => void;
  onTogglePinPost: (id: string) => void;
  onAddTeacher: (id: string, name: string, email?: string, phone?: string) => void;
  onSoftDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (project: Project) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
  onAddTempSupervisor: (user: User) => void;
  onUpdateSecurity: (backup: string, main?: string) => void;
  onUpdateLessonMaterial: (material: LessonMaterial) => void;
  backupPassword: string;
  academicYear: string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  user, teachers, posts, projects, lessonMaterials, resetRequests,
  onAddPost, onDeletePost, onTogglePinPost,
  onAddTeacher, onSoftDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateProjectSubmission,
  onAddTempSupervisor, onUpdateSecurity, onUpdateLessonMaterial,
  backupPassword, academicYear
}) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'projects' | 'lessons' | 'teachers' | 'team'>('feed');

  // Security State
  const [newBackupPass, setNewBackupPass] = useState(backupPassword);

  // Comment State
  const [commentText, setCommentText] = useState<Record<string, string>>({});
  const [editingCommentId, setEditingCommentId] = useState<string | null>(null);
  const [editCommentText, setEditCommentText] = useState('');

  // Temp Supervisor Form
  const [tempName, setTempName] = useState('');
  const [tempId, setTempId] = useState('');
  const [tempPermissions, setTempPermissions] = useState({ canViewTeachers: true, canComment: true, canApproveProjects: false });

  const handleAddComment = (material: LessonMaterial) => {
    const text = commentText[material.id];
    if (!text?.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      authorId: user.id,
      authorName: user.name,
      authorRole: user.role,
      text: text,
      createdAt: new Date().toLocaleString('ar-SA')
    };
    onUpdateLessonMaterial({ ...material, comments: [...material.comments, newComment] });
    setCommentText(prev => ({ ...prev, [material.id]: '' }));
  };

  const handleEditComment = (material: LessonMaterial, commentId: string) => {
    const updatedComments = material.comments.map(c => 
      c.id === commentId ? { ...c, text: editCommentText, isEdited: true } : c
    );
    onUpdateLessonMaterial({ ...material, comments: updatedComments });
    setEditingCommentId(null);
    setEditCommentText('');
  };

  const handleCreateTempSupervisor = (e: React.FormEvent) => {
    e.preventDefault();
    if (!tempName || !tempId) return;
    const newUser: User = {
      id: tempId,
      code: tempId,
      name: tempName,
      role: UserRole.TEMP_SUPERVISOR,
      password: `TEMP${tempId}`,
      isActive: true,
      joinedAt: academicYear,
      tempPermissions: tempPermissions
    };
    onAddTempSupervisor(newUser);
    setTempName('');
    setTempId('');
    alert('تمت إضافة المشرف المؤقت بنجاح');
  };

  const getFileIcon = (type: string, name: string) => {
    if (type === 'link') return '🔗';
    if (type === 'video') return '🎥';
    if (type === 'audio') return '🎙️';
    if (type === 'image') return '🖼️';
    return '📄';
  };

  return (
    <div className="space-y-8 pb-20 animate-fadeIn">
      {/* Navigation Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-4xl overflow-x-auto">
          {[
            { id: 'feed', label: '📢 التواصل', color: 'emerald' },
            { id: 'lessons', label: '🎨 ركن الإبداع', color: 'purple' },
            { id: 'projects', label: '🚀 المشاريع', color: 'teal' },
            { id: 'teachers', label: '👥 المعلمات', color: 'indigo' },
            { id: 'team', label: '⚙️ الفريق والأمان', color: 'slate' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[100px] px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                activeTab === tab.id ? `bg-emerald-600 text-white shadow-lg` : `text-slate-500 hover:bg-emerald-50`
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'lessons' && (
        <div className="space-y-8">
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <h3 className="text-2xl font-black text-slate-900">ركن الإبداع الدرسي</h3>
              <p className="text-slate-400 font-bold text-sm">متابعة المواد العلمية المرفوعة من المعلمات</p>
           </div>

           <div className="grid grid-cols-1 gap-6">
              {lessonMaterials.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-slate-200 font-bold text-slate-300">لا توجد مواد مرفوعة حالياً</div>
              ) : (
                lessonMaterials.map(material => (
                  <div key={material.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                     <div className="flex justify-between items-start mb-4">
                        <div>
                           <h4 className="text-xl font-black text-slate-900">{material.lessonTitle}</h4>
                           <span className="text-xs font-bold text-emerald-600">بواسطة: {material.teacherName}</span>
                        </div>
                        <span className="text-[10px] text-slate-400 font-bold">{material.createdAt}</span>
                     </div>
                     <p className="text-slate-600 font-bold text-sm mb-6 bg-slate-50 p-4 rounded-2xl">{material.description}</p>

                     <div className="flex flex-wrap gap-3 mb-8">
                        {material.attachments.map((att, i) => (
                          <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-indigo-50 px-4 py-2 rounded-xl border border-indigo-100 text-xs font-black text-indigo-700 hover:bg-indigo-100">
                             {getFileIcon(att.type, att.name)} {att.name} 📥
                          </a>
                        ))}
                     </div>

                     <div className="border-t border-slate-100 pt-6 space-y-4">
                        <h5 className="font-black text-slate-700 text-sm">سجل النقاش والتوجيه:</h5>
                        <div className="space-y-3">
                           {material.comments.map(c => (
                             <div key={c.id} className={`p-4 rounded-2xl text-sm ${c.authorRole === UserRole.TEACHER ? 'bg-indigo-50 mr-8 border-r-4 border-indigo-400' : 'bg-emerald-50 ml-8 border-r-4 border-emerald-400'}`}>
                                <div className="flex justify-between mb-1">
                                   <div className="flex items-center gap-2">
                                      <span className="font-black text-slate-800">{c.authorName}</span>
                                      {c.isEdited && <span className="text-[8px] font-bold text-slate-400 italic">(معدل)</span>}
                                   </div>
                                   <div className="flex items-center gap-2">
                                      <span className="text-[10px] text-slate-400">{c.createdAt}</span>
                                      {c.authorId === user.id && (
                                        <button onClick={() => { setEditingCommentId(c.id); setEditCommentText(c.text); }} className="text-slate-400 hover:text-emerald-600">✏️</button>
                                      )}
                                   </div>
                                </div>
                                {editingCommentId === c.id ? (
                                  <div className="space-y-2 mt-2">
                                     <textarea value={editCommentText} onChange={e => setEditCommentText(e.target.value)} className="w-full p-2 border rounded-xl text-xs font-bold" />
                                     <div className="flex gap-2">
                                        <button onClick={() => handleEditComment(material, c.id)} className="bg-emerald-600 text-white px-3 py-1 rounded-lg text-[10px] font-black">حفظ</button>
                                        <button onClick={() => setEditingCommentId(null)} className="bg-slate-200 text-slate-500 px-3 py-1 rounded-lg text-[10px] font-black">إلغاء</button>
                                     </div>
                                  </div>
                                ) : (
                                  <p className="font-bold text-slate-600">{c.text}</p>
                                )}
                             </div>
                           ))}
                        </div>
                        <div className="flex gap-2">
                           <input 
                             type="text" 
                             placeholder="إضافة تعليق توجيهي..." 
                             value={commentText[material.id] || ''} 
                             onChange={e => setCommentText({...commentText, [material.id]: e.target.value})}
                             className="flex-1 px-4 py-2 rounded-xl bg-slate-50 border border-slate-100 font-bold text-sm outline-none"
                           />
                           <button onClick={() => handleAddComment(material)} className="bg-emerald-600 text-white px-6 py-2 rounded-xl font-black text-xs">إرسال</button>
                        </div>
                     </div>
                  </div>
                ))
              )}
           </div>
        </div>
      )}

      {activeTab === 'team' && (
        <div className="space-y-8 max-w-4xl mx-auto">
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <h3 className="text-2xl font-black text-slate-900 mb-6">إعدادات الفريق والأمان</h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                 <div className="space-y-6">
                    <h4 className="font-black text-slate-800 border-b pb-2">🔐 أمان المشرفة الرئيسية</h4>
                    <div className="space-y-4">
                       <div>
                          <label className="text-xs font-black text-slate-500 mb-1 block">كلمة مرور احتياطية (للطوارئ)</label>
                          <input 
                            type="password" 
                            value={newBackupPass} 
                            onChange={e => setNewBackupPass(e.target.value)}
                            className="w-full px-4 py-3 rounded-xl bg-slate-50 border font-bold"
                            placeholder="أدخل كلمة مرور قوية..."
                          />
                       </div>
                       <button onClick={() => onUpdateSecurity(newBackupPass)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-black text-sm">حفظ إعدادات الأمان</button>
                    </div>
                 </div>

                 <div className="space-y-6">
                    <h4 className="font-black text-slate-800 border-b pb-2">👥 إضافة مشرف مؤقت</h4>
                    <form onSubmit={handleCreateTempSupervisor} className="space-y-4">
                       <input type="text" placeholder="اسم المشرف" value={tempName} onChange={e => setTempName(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-slate-50 border font-bold text-sm" />
                       <input type="text" placeholder="الرقم الوظيفي" value={tempId} onChange={e => setTempId(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-slate-50 border font-bold text-sm" />
                       <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase">الصلاحيات:</label>
                          <div className="flex flex-wrap gap-2">
                             {Object.entries(tempPermissions).map(([key, val]) => (
                               <label key={key} className="flex items-center gap-2 bg-slate-50 px-3 py-1 rounded-lg border cursor-pointer">
                                  <input type="checkbox" checked={val} onChange={() => setTempPermissions({...tempPermissions, [key]: !val})} />
                                  <span className="text-[10px] font-bold">{key === 'canViewTeachers' ? 'رؤية المعلمات' : key === 'canComment' ? 'التعليق' : 'الاعتماد'}</span>
                               </label>
                             ))}
                          </div>
                       </div>
                       <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-xl font-black text-sm shadow-md">إضافة للفريق</button>
                    </form>
                 </div>
              </div>
           </div>

           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <h4 className="font-black text-slate-800 mb-4">فريق الإشراف المضاف:</h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 {teachers.filter(t => t.role === UserRole.TEMP_SUPERVISOR).map(t => (
                   <div key={t.id} className="flex justify-between items-center bg-slate-50 p-4 rounded-2xl border">
                      <div>
                         <div className="font-black text-slate-800">{t.name}</div>
                         <div className="text-[10px] font-bold text-slate-400">كود الدخول: {t.code}</div>
                      </div>
                      <span className="bg-slate-200 text-slate-600 px-3 py-1 rounded-lg text-[9px] font-black">مشرف مؤقت</span>
                   </div>
                 ))}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

