  onAddTeacher: (id: string, name: string, email?: string, phone?: string) => void;
  onSoftDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (project: Project) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
  onAddTempSupervisor: (user: User) => void;
  onUpdateSecurity: (backup: string, main?: string) => void;
  onUpdateLessonMaterial: (material: LessonMaterial) => void;
  backupPassword: string;
  academicYear: string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  user, teachers, posts, projects, lessonMaterials, resetRequests,
  onAddPost, onDeletePost, onTogglePinPost,
  onAddTeacher, onSoftDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateProjectSubmission,
  onAddTempSupervisor, onUpdateSecurity, onUpdateLessonMaterial,
  backupPassword, academicYear
}) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'projects' | 'lessons' | 'teachers' | 'team'>('feed');

  // Security State
  const [newBackupPass, setNewBackupPass] = useState(backupPassword);

  // Comment State
  const [commentText, setCommentText] = useState<Record<string, string>>({});
  const [editingCommentId, setEditingCommentId] = useState<string | null>(null);
  const [editCommentText, setEditCommentText] = useState('');

  // Temp Supervisor Form
  const [tempName, setTempName] = useState('');
  const [tempId, setTempId] = useState('');
  const [tempPermissions, setTempPermissions] = useState({ canViewTeachers: true, canComment: true, canApproveProjects: false });

  // Reset Success State
  const [resetResult, setResetResult] = useState<{ name: string, pass: string, phone?: string } | null>(null);

  const handleAddComment = (material: LessonMaterial) => {
    const text = commentText[material.id];
    if (!text?.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      authorId: user.id,
      authorName: user.name,
      authorRole: user.role,
      text: text,
      createdAt: new Date().toLocaleString('ar-SA')
    };
    onUpdateLessonMaterial({ ...material, comments: [...material.comments, newComment] });
    setCommentText(prev => ({ ...prev, [material.id]: '' }));
  };

  const handleEditComment = (material: LessonMaterial, commentId: string) => {
    const updatedComments = material.comments.map(c => 
      c.id === commentId ? { ...c, text: editCommentText, isEdited: true } : c
    );
    onUpdateLessonMaterial({ ...material, comments: updatedComments });
    setEditingCommentId(null);
    setEditCommentText('');
  };

  const handleCreateTempSupervisor = (e: React.FormEvent) => {
    e.preventDefault();
    if (!tempName || !tempId) return;
    const newUser: User = {
      id: tempId,
      code: tempId,
      name: tempName,
      role: UserRole.TEMP_SUPERVISOR,
      password: `TEMP${tempId}`,
      isActive: true,
      joinedAt: academicYear,
      tempPermissions: tempPermissions
    };
    onAddTempSupervisor(newUser);
    setTempName('');
    setTempId('');
    alert('تمت إضافة المشرف المؤقت بنجاح');
  };

  const handleResetTeacherAction = (id: string, name: string) => {
    if (window.confirm(`هل أنتِ متأكدة من إعادة تعيين كلمة المرور للمعلمة ${name}؟`)) {
      const newPass = onResetPassword(id);
      const teacher = teachers.find(t => t.id === id);
      setResetResult({ name, pass: newPass, phone: teacher?.phoneNumber });
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text).then(() => {
      alert('تم نسخ كلمة المرور إلى الحافظة');
    });
  };

  const sendToWhatsApp = (phone: string, name: string, pass: string) => {
    const message = `السلام عليكم أ. ${name}%0Aتم إعادة تعيين كلمة المرور الخاصة بكِ في منصة الزيارات الإشرافية.%0Aكلمة المرور الجديدة هي: ${pass}`;
    window.open(`https://wa.me/${phone.replace(/\D/g, '')}?text=${message}`, '_blank');
  };

  const getFileIcon = (type: string, name: string) => {
    if (type === 'link') return '🔗';
    if (type === 'video') return '🎥';
    if (type === 'audio') return '🎙️';
    if (type === 'image') return '🖼️';
    return '📄';
  };

  const activeTeachers = useMemo(() => teachers.filter(t => t.isActive && t.role === UserRole.TEACHER), [teachers]);
  const pendingResets = useMemo(() => resetRequests.filter(r => r.status === 'pending'), [resetRequests]);

  return (
    <div className="space-y-8 pb-20 animate-fadeIn">
      {/* Reset Result Modal */}
      {resetResult && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[300] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl animate-slideIn text-center border-t-8 border-emerald-500">
            <div className="w-20 h-20 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✅</div>
            <h3 className="text-xl font-black text-slate-800 mb-2">تم إعادة التعيين بنجاح</h3>
            <p className="text-slate-500 text-xs font-bold mb-6">المعلمة: {resetResult.name}</p>

            <div className="bg-slate-50 p-6 rounded-2xl border-2 border-dashed border-slate-200 mb-6 relative group">
               <span className="text-[10px] font-black text-slate-400 absolute top-2 right-4">كلمة المرور الجديدة</span>
               <div className="text-2xl font-black text-slate-800 tracking-widest">{resetResult.pass}</div>
            </div>

            <div className="flex flex-col gap-3">
              <button onClick={() => copyToClipboard(resetResult.pass)} className="w-full bg-slate-900 text-white py-4 rounded-xl font-black text-sm shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                <span>📋</span> نسخ كلمة المرور
              </button>

              {resetResult.phone && (
                <button onClick={() => sendToWhatsApp(resetResult.phone!, resetResult.name, resetResult.pass)} className="w-full bg-[#25D366] text-white py-4 rounded-xl font-black text-sm shadow-lg hover:opacity-90 transition-all flex items-center justify-center gap-2">
                  <span>📱</span> إرسال عبر واتساب
                </button>
              )}

              <button onClick={() => setResetResult(null)} className="w-full text-slate-400 font-bold text-xs py-2">إغلاق النافذة</button>
            </div>
          </div>
        </div>
      )}

      {/* Navigation Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-4xl overflow-x-auto">
          {[
            { id: 'feed', label: '📢 التواصل', color: 'emerald' },
            { id: 'lessons', label: '🎨 ركن الإبداع', color: 'purple' },
            { id: 'projects', label: '🚀 المشاريع', color: 'teal' },
            { id: 'teachers', label: '👥 المعلمات', color: 'indigo' },
            { id: 'team', label: '⚙️ الفريق والأمان', color: 'slate' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[100px] px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                activeTab === tab.id ? `bg-emerald-600 text-white shadow-lg` : `text-slate-500 hover:bg-emerald-50`
              }`}
            >
              {tab.label}
              {tab.id === 'teachers' && pendingResets.length > 0 && (
                <span className="bg-red-500 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center animate-pulse">!</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'lessons' && (
        <div className="space-y-8">
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <h3 className="text-2xl font-black text-slate-900">ركن الإبداع الدرسي</h3>
              <p className="text-slate-400 font-bold text-sm">متابعة المواد العلمية المرفوعة من المعلمات</p>
           </div>

           <div className="grid grid-cols-1 gap-6">
              {lessonMaterials.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-slate-200 font-bold text-slate-300">لا توجد مواد مرفوعة حالياً</div>
              ) : (
                lessonMaterials.map(material => (
                  <div key={material.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                     <div className="flex justify-between items-start mb-4">
                        <div>
                           <h4 className="text-xl font-black text-slate-900">{material.lessonTitle}</h4>
                           <span className="text-xs font-bold text-emerald-600">بواسطة: {material.teacherName}</span>
                        </div>
                        <span className="text-[10px] text-slate-400 font-bold">{material.createdAt}</span>
                     </div>
                     <p className="text-slate-600 font-bold text-sm mb-6 bg-slate-50 p-4 rounded-2xl">{material.description}</p>

                     <div className="flex flex-wrap gap-3 mb-8">
                        {material.attachments.map((att, i) => (
                          <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-indigo-50 px-4 py-2 rounded-xl border border-indigo-100 text-xs font-black text-indigo-700 hover:bg-indigo-100">
                             {getFileIcon(att.type, att.name)} {att.name} 📥
                          </a>
                        ))}
                     </div>

                     <div className="border-t border-slate-100 pt-6 space-y-4">
                        <h5 className="font-black text-slate-700 text-sm">سجل النقاش والتوجيه:</h5>
                        <div className="space-y-3">
                           {material.comments.map(c => (
                             <div key={c.id} className={`p-4 rounded-2xl text-sm ${c.authorRole === UserRole.TEACHER ? 'bg-indigo-50 mr-8 border-r-4 border-indigo-400' : 'bg-emerald-50 ml-8 border-r-4 border-emerald-400'}`}>
                                <div className="flex justify-between mb-1">
                                   <div className="flex items-center gap-2">
                                      <span className="font-black text-slate-800">{c.authorName}</span>
                                      {c.isEdited && <span className="text-[8px] font-bold text-slate-400 italic">(معدل)</span>}
                                   </div>
                                   <div className="flex items-center gap-2">
                                      <span className="text-[10px] text-slate-400">{c.createdAt}</span>
                                      {c.authorId === user.id && (
                                        <button onClick={() => { setEditingCommentId(c.id); setEditCommentText(c.text); }} className="text-slate-400 hover:text-emerald-600">✏️</button>
                                      )}
                                   </div>
                                </div>
                                {editingCommentId === c.id ? (
                                  <div className="space-y-2 mt-2">
                                     <textarea value={editCommentText} onChange={e => setEditCommentText(e.target.value)} className="w-full p-2 border rounded-xl text-xs font-bold" />
                                     <div className="flex gap-2">
                                        <button onClick={() => handleEditComment(material, c.id)} className="bg-emerald-600 text-white px-3 py-1 rounded-lg text-[10px] font-black">حفظ</button>
                                        <button onClick={() => setEditingCommentId(null)} className="bg-slate-200 text-slate-500 px-3 py-1 rounded-lg text-[10px] font-black">إلغاء</button>
                                     </div>
                                  </div>
                                ) : (
                                  <p className="font-bold text-slate-600">{c.text}</p>
                                )}
                             </div>
                           ))}
                        </div>
                        <div className="flex gap-2">
                           <input 
                             type="text" 
                             placeholder="إضافة تعليق توجيهي..." 
                             value={commentText[material.id] || ''} 
                             onChange={e => setCommentText({...commentText, [material.id]: e.target.value})}
                             className="flex-1 px-4 py-2 rounded-xl bg-slate-50 border border-slate-100 font-bold text-sm outline-none"
                           />
                           <button onClick={() => handleAddComment(material)} className="bg-emerald-600 text-white px-6 py-2 rounded-xl font-black text-xs">إرسال</button>
                        </div>
                     </div>
                  </div>
                ))
              )}
           </div>
        </div>
      )}

      {activeTab === 'teachers' && (
        <div className="space-y-8 animate-fadeIn">
           <div className="flex justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <div>
                <h3 className="text-2xl font-black text-slate-900">سجل المعلمات</h3>
                <p className="text-slate-400 font-bold text-sm">إدارة البيانات والصلاحيات</p>
              </div>
           </div>

           {/* Pending Resets Notification */}
           {pendingResets.length > 0 && (
              <div className="bg-white p-6 rounded-[2.5rem] border-2 border-amber-200 space-y-4">
                 <h4 className="font-black text-amber-900 flex items-center gap-2">
                    <span>🔑</span> طلبات إعادة تعيين معلقة:
                 </h4>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {pendingResets.map(req => (
                       <div key={req.id} className="flex justify-between items-center bg-amber-50 p-4 rounded-2xl border border-amber-100">
                          <div>
                             <div className="font-black text-slate-800 text-xs">{req.userName}</div>
                             <div className="text-[10px] text-slate-500 font-bold">{req.requestedAt}</div>
                          </div>
                          <button 
                            onClick={() => handleResetTeacherAction(req.userId, req.userName)}
                            className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-[10px] font-black shadow-sm"
                          >
                             تصفير الآن
                          </button>
                       </div>
                    ))}
                 </div>
              </div>
           )}

           <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-right">
                  <thead className="bg-slate-50 border-b border-slate-100 text-slate-500 font-black text-xs">
                    <tr>
                      <th className="p-6">الاسم</th>
                      <th className="p-6">الرقم الوظيفي</th>
                      <th className="p-6 text-center">إجراءات الحساب</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {activeTeachers.map(teacher => (
                      <tr key={teacher.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="p-6 font-bold text-slate-800">{teacher.name}</td>
                        <td className="p-6 font-bold text-slate-500 font-mono">{teacher.code}</td>
                        <td className="p-6">
                           <div className="flex justify-center gap-2">
                             <button 
                               onClick={() => handleResetTeacherAction(teacher.id, teacher.name)} 
                               className={`px-4 py-2 rounded-xl text-xs font-black transition-all flex items-center gap-2 ${pendingResets.find(r => r.userId === teacher.id) ? 'bg-amber-100 text-amber-600 ring-2 ring-amber-400' : 'bg-slate-100 text-slate-600 hover:bg-amber-50 hover:text-amber-600'}`}
                             >
                               🔑 إعادة التعيين
                             </button>
                             <button onClick={() => onSoftDeleteTeacher(teacher.id)} className="bg-red-50 text-red-600 px-4 py-2 rounded-xl text-xs font-black hover:bg-red-100">
                               🗑️ حذف
                             </button>
                           </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'team' && (
        <div className="space-y-8 max-w-4xl mx-auto">
           {/* Team and Security Section - already implemented in previous turn */}
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 text-center">
              <h3 className="text-xl font-black text-slate-800 mb-4">إعدادات الأمان</h3>
              <div className="max-w-xs mx-auto space-y-4">
                 <input 
                   type="password" 
                   value={newBackupPass} 
                   onChange={e => setNewBackupPass(e.target.value)}
                   className="w-full px-4 py-3 rounded-xl bg-slate-50 border font-bold text-center"
                   placeholder="كلمة مرور الطوارئ"
                 />
                 <button onClick={() => onUpdateSecurity(newBackupPass)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-black">حفظ التغييرات</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default SupervisorDashboard;

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Project, Post, ResetRequest, LessonMaterial, Comment } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const CURRENT_ACADEMIC_YEAR = "2025-2026";
const APP_TITLE = "الزيارات الإشرافية للمجال الأول";

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [lessonMaterials, setLessonMaterials] = useState<LessonMaterial[]>(() => {
    const saved = localStorage.getItem('app_lesson_materials');
    return saved ? JSON.parse(saved) : [];
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('app_projects');
    return saved ? JSON.parse(saved) : [];
  });

  const [posts, setPosts] = useState<Post[]>(() => {
    const saved = localStorage.getItem('app_posts');
    return saved ? JSON.parse(saved) : [];
  });

  const [resetRequests, setResetRequests] = useState<ResetRequest[]>(() => {
    const saved = localStorage.getItem('app_reset_requests');
    return saved ? JSON.parse(saved) : [];
  });

  const [supervisorConfig, setSupervisorConfig] = useState(() => {
    const saved = localStorage.getItem('app_supervisor_config');
    return saved ? JSON.parse(saved) : { backupPassword: '' };
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  useEffect(() => {
    localStorage.setItem('app_lesson_materials', JSON.stringify(lessonMaterials));
  }, [lessonMaterials]);

  useEffect(() => {
    localStorage.setItem('app_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem('app_posts', JSON.stringify(posts));
  }, [posts]);

  useEffect(() => {
    localStorage.setItem('app_reset_requests', JSON.stringify(resetRequests));
  }, [resetRequests]);

  useEffect(() => {
    localStorage.setItem('app_supervisor_config', JSON.stringify(supervisorConfig));
  }, [supervisorConfig]);

  const handleLogin = (user: User) => {
    if (!user.isActive) {
      alert('عذراً، هذا الحساب غير نشط.');
      return;
    }
    setAuth({ user, isAuthenticated: true });
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setShowChangePassword(true);
    } else {
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const handleUpdateLessonMaterial = (updated: LessonMaterial) => {
    setLessonMaterials(prev => prev.map(m => m.id === updated.id ? updated : m));
  };

  const handleResetPassword = (id: string) => {
    const defaultPass = `OM${id}`;
    // Update teacher password
    setTeachers(prev => prev.map(t => 
      t.id === id ? { ...t, password: defaultPass, mustChangePassword: true } : t
    ));
    // Clear the request from pending
    setResetRequests(prev => prev.filter(req => req.userId !== id));
    return defaultPass;
  };

  const handleForgotPasswordRequest = (userId: string) => {
    const teacher = teachers.find(t => t.id === userId && t.isActive);
    if (!teacher) {
      alert('المعلمة غير موجودة أو الحساب معطل.');
      return;
    }
    const newRequest: ResetRequest = {
      id: Date.now().toString(),
      userId: teacher.id,
      userName: teacher.name,
      requestedAt: new Date().toLocaleString('ar-SA'),
      status: 'pending'
    };
    setResetRequests(prev => {
      if (prev.find(r => r.userId === userId)) return prev;
      return [newRequest, ...prev];
    });
    alert('تم إرسال طلب تصفير كلمة المرور للمشرفة.');
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false, password: newPassword } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm 
      onLogin={handleLogin} 
      teachers={teachers} 
      onForgotPassword={handleForgotPasswordRequest}
      backupPassword={supervisorConfig.backupPassword}
    />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm 
      onPasswordChanged={handlePasswordChanged} 
      onLogout={handleLogout} 
      currentPassword={auth.user?.password}
    />;
  }

  return (
    <div className="min-h-screen bg-[#f8fafc] font-['Tajawal'] antialiased">
      <nav className="bg-white/90 backdrop-blur-md text-slate-900 shadow-sm sticky top-0 z-[100] border-b border-slate-100 h-20 flex items-center">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="bg-gradient-to-tr from-emerald-600 to-teal-600 p-2.5 rounded-2xl shadow-lg shadow-emerald-100">
                <span className="text-2xl">📋</span>
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black tracking-tight text-slate-900 leading-none mb-1">{APP_TITLE}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">المجال الأول - العام الدراسي {CURRENT_ACADEMIC_YEAR}</span>
              </div>
            </div>
            <div className="flex items-center gap-4 md:gap-6">
              <div className="hidden md:flex flex-col items-end text-left">
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
                <span className="text-[10px] font-bold text-emerald-500 uppercase">
                  {auth.user?.role === UserRole.SUPERVISOR ? 'مشرفة النظام' : 
                   auth.user?.role === UserRole.TEMP_SUPERVISOR ? 'مشرفة مؤقتة' : 'عضو هيئة التدريس'}
                </span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-slate-50 text-slate-600 hover:bg-red-50 hover:text-red-600 px-5 py-2.5 rounded-xl text-xs font-black transition-all active:scale-95 border border-slate-100"
              >
                تسجيل الخروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            posts={posts}
            projects={projects}
            lessonMaterials={lessonMaterials}
            onAddMaterial={(m) => setLessonMaterials(prev => [m, ...prev])}
            onUpdateMaterial={handleUpdateLessonMaterial}
            updateProjectSubmission={(pid, sub) => {
               setProjects(prev => prev.map(p => p.id === pid ? { ...p, submissions: { ...p.submissions, [sub.teacherId]: sub } } : p));
            }}
          />
        ) : (
          <SupervisorDashboard 
            user={auth.user}
            teachers={teachers}
            posts={posts}
            projects={projects}
            lessonMaterials={lessonMaterials}
            resetRequests={resetRequests}
            onAddPost={(p) => setPosts(prev => [p, ...prev])}
            onDeletePost={(id) => setPosts(prev => prev.filter(p => p.id !== id))}
            onTogglePinPost={(id) => setPosts(prev => prev.map(p => p.id === id ? { ...p, isPinned: !p.isPinned } : p))}
            onAddTeacher={(id, name, email, phone) => {
              const defaultPass = `OM${id}`;
              setTeachers(prev => [...prev, { id, code: id, name, role: UserRole.TEACHER, password: defaultPass, mustChangePassword: true, isActive: true, joinedAt: CURRENT_ACADEMIC_YEAR, email, phoneNumber: phone }]);
            }}
            onSoftDeleteTeacher={(id) => setTeachers(prev => prev.map(t => t.id === id ? { ...t, isActive: false } : t))}
            onResetPassword={handleResetPassword}
            onAddProject={(p) => setProjects(prev => [p, ...prev])}
            onDeleteProject={(id) => setProjects(prev => prev.filter(p => p.id !== id))}
            onUpdateProjectSubmission={(pid, sub) => {
               setProjects(prev => prev.map(p => p.id === pid ? { ...p, submissions: { ...p.submissions, [sub.teacherId]: sub } } : p));
            }}
            onAddTempSupervisor={(u) => setTeachers(prev => [...prev, u])}
            onUpdateSecurity={(back) => setSupervisorConfig({ backupPassword: back })}
            onUpdateLessonMaterial={handleUpdateLessonMaterial}
            backupPassword={supervisorConfig.backupPassword}
            academicYear={CURRENT_ACADEMIC_YEAR}
          />
        )}
      </main>

      <footer className="py-8 text-center text-slate-400 text-[10px] font-bold border-t border-slate-100 mt-12 bg-white/50">
        جميع الحقوق محفوظة - {APP_TITLE} © {CURRENT_ACADEMIC_YEAR}
      </footer>
    </div>
  );
};

export default App;

export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR',
  TEMP_SUPERVISOR = 'TEMP_SUPERVISOR'
}

export interface TempPermissions {
  canViewTeachers: boolean;
  canComment: boolean;
  canApproveProjects: boolean;
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
  mustChangePassword?: boolean;
  isActive: boolean;
  joinedAt: string;
  email?: string;
  phoneNumber?: string;
  tempPermissions?: TempPermissions; // For Temp Supervisors
}

export interface SupervisorConfig {
  mainPassword?: string;
  backupPassword?: string;
}

export interface Comment {
  id: string;
  authorId: string;
  authorName: string;
  authorRole: UserRole;
  text: string;
  createdAt: string;
  isEdited?: boolean;
}

export interface LessonMaterial {
  id: string;
  teacherId: string;
  teacherName: string;
  lessonTitle: string;
  description: string;
  attachments: Attachment[];
  comments: Comment[];
  createdAt: string;
  academicYear: string;
}

export interface ResetRequest {
  id: string;
  userId: string;
  userName: string;
  requestedAt: string;
