                                   <div className="flex items-center gap-2">
                                      <span className="text-[10px] text-slate-400 font-bold">{c.createdAt}</span>
                                      {c.authorId === user.id && (
                                        <button onClick={() => { setEditingCommentId(c.id); setEditCommentText(c.text); }} className="text-slate-300 hover:text-emerald-600 transition-colors">✏️</button>
                                      )}
                                   </div>
                                </div>
                                {editingCommentId === c.id ? (
                                  <div className="space-y-2 mt-2">
                                     <textarea value={editCommentText} onChange={e => setEditCommentText(e.target.value)} className="w-full p-3 border rounded-2xl text-xs font-bold outline-none focus:border-emerald-500" rows={2} />
                                     <div className="flex gap-2">
                                        <button onClick={() => handleEditComment(material, c.id)} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-[10px] font-black shadow-md">تحديث</button>
                                        <button onClick={() => setEditingCommentId(null)} className="bg-slate-200 text-slate-500 px-4 py-2 rounded-xl text-[10px] font-black">إلغاء</button>
                                     </div>
                                  </div>
                                ) : (
                                  <p className="font-bold text-slate-600 leading-relaxed">{c.text}</p>
                                )}
                             </div>
                           ))}
                        </div>
                        <div className="flex gap-2 bg-slate-50 p-2 rounded-2xl border border-slate-100 mt-4">
                           <input 
                             type="text" 
                             placeholder="أضف توجيهاً أو تعليقاً للمعلمة..." 
                             value={commentText[material.id] || ''} 
                             onChange={e => setCommentText({...commentText, [material.id]: e.target.value})}
                             className="flex-1 px-5 py-3 rounded-xl bg-white border border-slate-100 font-bold text-sm outline-none focus:border-emerald-500 transition-all"
                           />
                           <button onClick={() => handleAddComment(material)} className="bg-emerald-600 text-white px-8 py-3 rounded-xl font-black text-xs shadow-lg hover:bg-emerald-700 transition-all active:scale-95">إرسال</button>
                        </div>
                     </div>
                  </div>
                ))
              )}
           </div>
        </div>
      )}

      {activeTab === 'teachers' && (
        <div className="space-y-8 animate-fadeIn">
           <div className="flex justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <div>
                <h3 className="text-2xl font-black text-slate-900">سجل الكادر التعليمي</h3>
                <p className="text-slate-400 font-bold text-sm">إدارة الحسابات وكلمات المرور</p>
              </div>
           </div>

           {pendingResets.length > 0 && (
              <div className="bg-white p-8 rounded-[2.5rem] border-2 border-amber-200 shadow-xl shadow-amber-50 space-y-5 animate-pulse-subtle">
                 <h4 className="font-black text-amber-900 flex items-center gap-3 text-lg">
                    <span className="text-2xl">🔔</span> طلبات إعادة تعيين كلمة المرور المعلقة:
                 </h4>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {pendingResets.map(req => (
                       <div key={req.id} className="flex justify-between items-center bg-amber-50 p-6 rounded-[2rem] border border-amber-100 group hover:bg-amber-100 transition-all">
                          <div>
                             <div className="font-black text-slate-800 text-sm mb-1">{req.userName}</div>
                             <div className="text-[10px] text-slate-500 font-bold flex items-center gap-1">🕒 {req.requestedAt}</div>
                          </div>
                          <button 
                            onClick={() => handleResetTeacherAction(req.userId, req.userName)}
                            className="bg-emerald-600 text-white px-6 py-3 rounded-2xl text-[10px] font-black shadow-lg hover:bg-emerald-700 transition-all active:scale-95"
                          >
                             إعادة تعيين الآن
                          </button>
                       </div>
                    ))}
                 </div>
              </div>
           )}

           <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
              <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-right">
                  <thead className="bg-slate-50 border-b border-slate-100 text-slate-500 font-black text-xs">
                    <tr>
                      <th className="p-8">الاسم الكامل</th>
                      <th className="p-8">الرقم الوظيفي</th>
                      <th className="p-8 text-center">الإجراءات</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {activeTeachers.map(teacher => (
                      <tr key={teacher.id} className="hover:bg-slate-50/50 transition-colors group">
                        <td className="p-8 font-black text-slate-800">{teacher.name}</td>
                        <td className="p-8 font-bold text-slate-500 font-mono tracking-wider">{teacher.code}</td>
                        <td className="p-8">
                           <div className="flex justify-center gap-3">
                             <button 
                               onClick={() => handleResetTeacherAction(teacher.id, teacher.name)} 
                               className={`px-5 py-3 rounded-2xl text-xs font-black transition-all flex items-center gap-2 ${pendingResets.find(r => r.userId === teacher.id) ? 'bg-amber-100 text-amber-700 ring-2 ring-amber-400' : 'bg-slate-100 text-slate-600 hover:bg-emerald-50 hover:text-emerald-700'}`}
                             >
                               🔑 إعادة التعيين
                             </button>
                             <button onClick={() => onSoftDeleteTeacher(teacher.id)} className="bg-red-50 text-red-600 px-5 py-3 rounded-2xl text-xs font-black hover:bg-red-100 transition-colors">
                               🗑️ أرشفة
                             </button>
                           </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'team' && (
        <div className="space-y-8 max-w-4xl mx-auto animate-fadeIn">
           <div className="bg-white p-10 rounded-[3.5rem] shadow-sm border border-slate-100 space-y-10">
              <div className="text-center">
                 <h3 className="text-2xl font-black text-slate-900 mb-2">إدارة أمان النظام</h3>
                 <p className="text-slate-400 text-sm font-bold">تعديل كلمات المرور الرئيسية والاحتياطية</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                 <div className="bg-slate-50/50 p-8 rounded-[2.5rem] border border-slate-100 space-y-6">
                    <h4 className="font-black text-slate-800 flex items-center gap-2 text-sm border-b border-slate-200 pb-3">
                       🛡️ كلمة المرور الرئيسية
                    </h4>
                    <div className="space-y-4">
                       <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">كلمة المرور الحالية/الجديدة</label>
                          <input 
                            type="password" 
                            value={newMainPass} 
                            onChange={e => setNewMainPass(e.target.value)}
                            className="w-full px-5 py-4 rounded-2xl bg-white border border-slate-200 font-black text-center focus:border-emerald-500 outline-none"
                            placeholder="أدخل كلمة المرور الجديدة"
                          />
                       </div>
                       <p className="text-[9px] text-slate-400 font-bold leading-relaxed">هذه الكلمة تستخدم للدخول الرسمي للمشرفة الرئيسية.</p>
                    </div>
                 </div>

                 <div className="bg-amber-50/30 p-8 rounded-[2.5rem] border border-amber-100 space-y-6">
                    <h4 className="font-black text-amber-900 flex items-center gap-2 text-sm border-b border-amber-100 pb-3">
                       🔐 كلمة مرور الطوارئ (الاحتياطية)
                    </h4>
                    <div className="space-y-4">
                       <div>
                          <label className="text-[10px] font-black text-amber-600 uppercase tracking-widest block mb-2">كلمة المرور الاحتياطية</label>
                          <input 
                            type="password" 
                            value={newBackupPass} 
                            onChange={e => setNewBackupPass(e.target.value)}
                            className="w-full px-5 py-4 rounded-2xl bg-white border border-amber-200 font-black text-center focus:border-amber-500 outline-none"
                            placeholder="تعيين كود الطوارئ"
                          />
                       </div>
                       <p className="text-[9px] text-amber-700/60 font-bold leading-relaxed">تستخدم هذه الكلمة في حال نسيان الكلمة الرئيسية، يرجى حفظها في مكان آمن.</p>
                    </div>
                 </div>
              </div>

              <div className="pt-6">
                 <button 
                   onClick={() => onUpdateSecurity(newBackupPass, newMainPass)} 
                   className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-lg shadow-2xl hover:bg-emerald-600 transition-all active:scale-95"
                 >
                   تحديث إعدادات الأمان 🔒
                 </button>
              </div>
           </div>

           {/* Add Temp Supervisor Section - preserved from before */}
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3">
                 <span>👥</span> إضافة مساعد إشراف (مشرف مؤقت)
              </h4>
              <form onSubmit={handleCreateTempSupervisor} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <input type="text" placeholder="اسم المشرف" value={tempName} onChange={e => setTempName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border font-bold" />
                 <input type="text" placeholder="الرقم الوظيفي" value={tempId} onChange={e => setTempId(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border font-bold" />
                 <button type="submit" className="md:col-span-2 bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg">إضافة المشرف للفريق ➕</button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default SupervisorDashboard;

{
  "name": "منصة الإبداع للمجال الأول",
  "description": "منصة إلكترونية متكاملة لإدارة الزيارات الإشرافية والمشاريع التربوية للمجال الأول.",
  "requestFramePermissions": []
}

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Project, Post, ResetRequest, LessonMaterial, Comment, SupervisorConfig } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const CURRENT_ACADEMIC_YEAR = "2025-2026";
const APP_TITLE = "منصة الإبداع للمجال الأول";

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [lessonMaterials, setLessonMaterials] = useState<LessonMaterial[]>(() => {
    const saved = localStorage.getItem('app_lesson_materials');
    return saved ? JSON.parse(saved) : [];
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('app_projects');
    return saved ? JSON.parse(saved) : [];
  });

  const [posts, setPosts] = useState<Post[]>(() => {
    const saved = localStorage.getItem('app_posts');
    return saved ? JSON.parse(saved) : [];
  });

  const [resetRequests, setResetRequests] = useState<ResetRequest[]>(() => {
    const saved = localStorage.getItem('app_reset_requests');
    return saved ? JSON.parse(saved) : [];
  });

  const [supervisorConfig, setSupervisorConfig] = useState<SupervisorConfig>(() => {
    const saved = localStorage.getItem('app_supervisor_config');
    return saved ? JSON.parse(saved) : { mainPassword: '', backupPassword: '' };
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  useEffect(() => {
    localStorage.setItem('app_lesson_materials', JSON.stringify(lessonMaterials));
  }, [lessonMaterials]);

  useEffect(() => {
    localStorage.setItem('app_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem('app_posts', JSON.stringify(posts));
  }, [posts]);

  useEffect(() => {
    localStorage.setItem('app_reset_requests', JSON.stringify(resetRequests));
  }, [resetRequests]);

  useEffect(() => {
    localStorage.setItem('app_supervisor_config', JSON.stringify(supervisorConfig));
  }, [supervisorConfig]);

  const handleLogin = (user: User) => {
    if (!user.isActive) {
      alert('عذراً، هذا الحساب غير نشط.');
      return;
    }
    setAuth({ user, isAuthenticated: true });
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setShowChangePassword(true);
    } else {
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const handleUpdateLessonMaterial = (updated: LessonMaterial) => {
    setLessonMaterials(prev => prev.map(m => m.id === updated.id ? updated : m));
  };

  const handleResetPassword = (id: string) => {
    const defaultPass = `OM${id}`;
    // Update teacher password in the list
    setTeachers(prev => {
      const newList = prev.map(t => 
        t.id === id ? { ...t, password: defaultPass, mustChangePassword: true } : t
      );
      return newList;
    });
    // Clear the request from pending
    setResetRequests(prev => prev.filter(req => req.userId !== id));
    return defaultPass;
  };

  const handleForgotPasswordRequest = (userId: string) => {
    const teacher = teachers.find(t => t.id === userId && t.isActive);
    if (!teacher) {
      alert('المعلمة غير موجودة أو الحساب معطل.');
      return;
    }
    const newRequest: ResetRequest = {
      id: Date.now().toString(),
      userId: teacher.id,
      userName: teacher.name,
      requestedAt: new Date().toLocaleString('ar-SA'),
      status: 'pending'
    };
    setResetRequests(prev => {
      if (prev.find(r => r.userId === userId)) return prev;
      return [newRequest, ...prev];
    });
    alert('تم إرسال طلب تصفير كلمة المرور للمشرفة.');
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false, password: newPassword } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm 
      onLogin={handleLogin} 
      teachers={teachers} 
      onForgotPassword={handleForgotPasswordRequest}
      supervisorConfig={supervisorConfig}
    />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm 
      onPasswordChanged={handlePasswordChanged} 
      onLogout={handleLogout} 
      currentPassword={auth.user?.password}
    />;
  }

  return (
    <div className="min-h-screen bg-[#f8fafc] font-['Tajawal'] antialiased">
      <nav className="bg-white/90 backdrop-blur-md text-slate-900 shadow-sm sticky top-0 z-[100] border-b border-slate-100 h-20 flex items-center">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="bg-gradient-to-tr from-emerald-600 to-teal-600 p-2.5 rounded-2xl shadow-lg shadow-emerald-100">
                <span className="text-2xl">📋</span>
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black tracking-tight text-slate-900 leading-none mb-1">{APP_TITLE}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">المجال الأول - العام الدراسي {CURRENT_ACADEMIC_YEAR}</span>
              </div>
            </div>
            <div className="flex items-center gap-4 md:gap-6">
              <div className="hidden md:flex flex-col items-end text-left">
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
                <span className="text-[10px] font-bold text-emerald-500 uppercase">
                  {auth.user?.role === UserRole.SUPERVISOR ? 'مشرفة النظام' : 
                   auth.user?.role === UserRole.TEMP_SUPERVISOR ? 'مشرفة مؤقتة' : 'عضو هيئة التدريس'}
                </span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-slate-50 text-slate-600 hover:bg-red-50 hover:text-red-600 px-5 py-2.5 rounded-xl text-xs font-black transition-all active:scale-95 border border-slate-100"
              >
                تسجيل الخروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            posts={posts}
            projects={projects}
            lessonMaterials={lessonMaterials}
            onAddMaterial={(m) => setLessonMaterials(prev => [m, ...prev])}
            onUpdateMaterial={handleUpdateLessonMaterial}
            updateProjectSubmission={(pid, sub) => {
               setProjects(prev => prev.map(p => p.id === pid ? { ...p, submissions: { ...p.submissions, [sub.teacherId]: sub } } : p));
            }}
          />
        ) : (
          <SupervisorDashboard 
            user={auth.user}
            teachers={teachers}
            posts={posts}
            projects={projects}
            lessonMaterials={lessonMaterials}
            resetRequests={resetRequests}
            onAddPost={(p) => setPosts(prev => [p, ...prev])}
            onDeletePost={(id) => setPosts(prev => prev.filter(p => p.id !== id))}
            onTogglePinPost={(id) => setPosts(prev => prev.map(p => p.id === id ? { ...p, isPinned: !p.isPinned } : p))}
            onAddTeacher={(id, name, email, phone) => {
              const defaultPass = `OM${id}`;
              setTeachers(prev => [...prev, { id, code: id, name, role: UserRole.TEACHER, password: defaultPass, mustChangePassword: true, isActive: true, joinedAt: CURRENT_ACADEMIC_YEAR, email, phoneNumber: phone }]);
            }}
            onSoftDeleteTeacher={(id) => setTeachers(prev => prev.map(t => t.id === id ? { ...t, isActive: false } : t))}
            onResetPassword={handleResetPassword}
            onAddProject={(p) => setProjects(prev => [p, ...prev])}
            onDeleteProject={(id) => setProjects(prev => prev.filter(p => p.id !== id))}
            onUpdateProjectSubmission={(pid, sub) => {
               setProjects(prev => prev.map(p => p.id === pid ? { ...p, submissions: { ...p.submissions, [sub.teacherId]: sub } } : p));
            }}
            onAddTempSupervisor={(u) => setTeachers(prev => [...prev, u])}
            onUpdateSecurity={(back, main) => setSupervisorConfig({ backupPassword: back, mainPassword: main })}
            onUpdateLessonMaterial={handleUpdateLessonMaterial}
            supervisorConfig={supervisorConfig}
            academicYear={CURRENT_ACADEMIC_YEAR}
          />
        )}
      </main>

      <footer className="py-8 text-center text-slate-400 text-[10px] font-bold border-t border-slate-100 mt-12 bg-white/50">
        جميع الحقوق محفوظة - {APP_TITLE} © {CURRENT_ACADEMIC_YEAR}
      </footer>
    </div>
  );
};

