export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR',
  TEMP_SUPERVISOR = 'TEMP_SUPERVISOR'
}

export interface TempPermissions {
  canViewTeachers: boolean;
  canComment: boolean;
  canApproveProjects: boolean;
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
  mustChangePassword?: boolean;
  isActive: boolean;
  joinedAt: string;
  email?: string;
  phoneNumber?: string;
  subject?: string; // المادة: لغة عربية، إسلامية، دراسات
  teachingGrades?: string; // الصفوف التي تدرسها
  tempPermissions?: TempPermissions; // For Temp Supervisors
}

export interface SupervisorConfig {
  mainPassword?: string;
  backupPassword?: string;
  academicYear?: string; // السنة الدراسية (نص)
  semester?: string; // الفصل الدراسي (نص)
}

export interface Comment {
  id: string;
  authorId: string;
  authorName: string;
  authorRole: UserRole;
  text: string;
  createdAt: string;
  isEdited?: boolean;
}

export interface LessonMaterial {
  id: string;
  teacherId: string;
  teacherName: string;
  lessonTitle: string;
  description: string;
  attachments: Attachment[];
  comments: Comment[];
  createdAt: string;
  academicYear: string;
}

export interface ResetRequest {
  id: string;
  userId: string;
  userName: string;
  requestedAt: string;
  status: 'pending' | 'resolved';
}

export type AttachmentType = 'link' | 'image' | 'video' | 'audio' | 'file';

export interface Attachment {
  type: AttachmentType;
  url: string;
  name: string;
}

export interface Post {
  id: string;
  authorId: string;
  authorName: string;
  title: string;
  content: string;
  attachments: Attachment[];
  isPinned: boolean;
  createdAt: string;
  academicYear: string;
}

export interface ProjectSubmission {
  teacherId: string;
  files: Attachment[];
  notes: string;
  status: 'pending' | 'submitted' | 'approved' | 'needs_work';
  feedback: string;
  badges: string[];
  submittedAt?: string;
}

export interface Project {
  id: string;
  name: string;
  description: string;
  tasks: string[];
  assignedTeacherIds: string[];
  createdAt: string;
  academicYear: string;
  submissions: Record<string, ProjectSubmission>;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

