  const [newLessonDesc, setNewLessonDesc] = useState('');
  const [materialFiles, setMaterialFiles] = useState<Attachment[]>([]);
  const [commentText, setCommentText] = useState('');

  const myMaterials = lessonMaterials.filter(m => m.teacherId === user.id);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'material' | 'project') => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      let type: AttachmentType = 'file';
      if (file.type.startsWith('image')) type = 'image';
      else if (file.type.startsWith('video')) type = 'video';
      else if (file.type.startsWith('audio')) type = 'audio';

      reader.onload = () => {
        const newAtt = { type, url: reader.result as string, name: file.name };
        if (target === 'material') setMaterialFiles(prev => [...prev, newAtt]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveMaterial = () => {
    if (!newLessonTitle) return alert('يرجى إدخال عنوان الدرس');
    const material: LessonMaterial = {
      id: Date.now().toString(),
      teacherId: user.id,
      teacherName: user.name,
      lessonTitle: newLessonTitle,
      description: newLessonDesc,
      attachments: materialFiles,
      comments: [],
      createdAt: new Date().toLocaleDateString('ar-SA'),
      academicYear: currentYear
    };
    onAddMaterial(material);
    setNewLessonTitle('');
    setNewLessonDesc('');
    setMaterialFiles([]);
    alert('تمت إضافة مادة الدرس بنجاح');
  };

  const handleAddComment = (material: LessonMaterial) => {
    if (!commentText.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      authorId: user.id,
      authorName: user.name,
      authorRole: UserRole.TEACHER,
      text: commentText,
      createdAt: new Date().toLocaleString('ar-SA')
    };
    onUpdateMaterial({ ...material, comments: [...material.comments, newComment] });
    setCommentText('');
  };

  const getFileIcon = (type: string, name: string) => {
    if (type === 'link') return '🔗';
    if (type === 'video') return '🎥';
    if (type === 'audio') return '🎙️';
    if (type === 'image') return '🖼️';
    return '📄';
  };

  return (
    <div className="pb-24 animate-fadeIn">
      <div className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-100 p-4 z-50 flex justify-around md:static md:bg-transparent md:border-0 md:p-0 md:justify-center md:mb-10">
         <div className="bg-white p-1.5 md:p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-xl">
            {[
              { id: 'feed', icon: '📢', label: 'الرئيسية' },
              { id: 'lessons', icon: '🎨', label: 'إبداع درسي' },
              { id: 'my-projects', icon: '🚀', label: 'مشاريعي' },
              { id: 'badges', icon: '🏆', label: 'أوسمتي' }
            ].map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveView(item.id as any); setSelectedProjectId(null); setSelectedMaterialId(null); }}
                className={`flex-1 px-4 py-3 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                  activeView === item.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <span>{item.icon}</span>
                <span className="hidden sm:inline">{item.label}</span>
              </button>
            ))}
         </div>
      </div>

      {activeView === 'lessons' && (
        <div className="max-w-4xl mx-auto space-y-8">
           <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
              <h3 className="text-2xl font-black text-slate-800 mb-6">إضافة مادة درسية جديدة</h3>
              <div className="space-y-4">
                 <input 
                   type="text" 
                   placeholder="عنوان الدرس" 
                   value={newLessonTitle} 
                   onChange={e => setNewLessonTitle(e.target.value)}
                   className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-400 outline-none font-bold"
                 />
                 <textarea 
                   placeholder="وصف موجز للدرس..." 
                   value={newLessonDesc} 
                   onChange={e => setNewLessonDesc(e.target.value)}
                   className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-400 outline-none font-bold min-h-[100px]"
                 />
                 <div className="flex gap-4">
                   <label className="flex-1 cursor-pointer bg-indigo-50 text-indigo-600 px-6 py-4 rounded-2xl font-black text-center border-2 border-dashed border-indigo-200">
                      + إضافة مرفقات (PPT, PDF, Video, Image)
                      <input type="file" onChange={e => handleFileUpload(e, 'material')} className="hidden" />
                   </label>
                 </div>
                 {materialFiles.length > 0 && (
                   <div className="flex flex-wrap gap-2">
                     {materialFiles.map((f, i) => (
                       <span key={i} className="bg-slate-100 px-3 py-1 rounded-lg text-xs font-bold">{getFileIcon(f.type, f.name)} {f.name}</span>
                     ))}
                   </div>
                 )}
                 <button onClick={handleSaveMaterial} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg">حفظ المادة الدراسية</button>
              </div>
           </div>

           <div className="grid grid-cols-1 gap-6">
              {myMaterials.map(material => (
                <div key={material.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                   <div className="flex justify-between items-start mb-4">
                      <h4 className="text-xl font-black text-slate-900">{material.lessonTitle}</h4>
                      <span className="text-[10px] text-slate-400 font-bold">{material.createdAt}</span>
                   </div>
                   <p className="text-slate-600 font-bold text-sm mb-6">{material.description}</p>

                   <div className="flex flex-wrap gap-3 mb-6">
                      {material.attachments.map((att, i) => (
                        <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-xl border border-slate-100 text-xs font-black text-indigo-600 hover:bg-indigo-50">
                           {getFileIcon(att.type, att.name)} {att.name}
                        </a>
                      ))}
                   </div>

                   <div className="border-t border-slate-100 pt-6 space-y-4">
                      <h5 className="font-black text-slate-700 text-sm">التواصل مع المشرفة ({material.comments.length}):</h5>
                      <div className="space-y-3">
                         {material.comments.map(c => (
                           <div key={c.id} className={`p-4 rounded-2xl text-sm ${c.authorRole === UserRole.TEACHER ? 'bg-indigo-50 mr-8' : 'bg-emerald-50 ml-8 border-r-4 border-emerald-400'}`}>
                              <div className="flex justify-between mb-1">
                                 <span className="font-black text-slate-800">{c.authorName}</span>
                                 <span className="text-[10px] text-slate-400">{c.createdAt}</span>
                              </div>
                              <p className="font-bold text-slate-600">{c.text}</p>
                           </div>
                         ))}
                      </div>
                      <div className="flex gap-2">
                         <input 
                           type="text" 
                           placeholder="أكتبي رداً أو استفساراً..." 
                           value={commentText} 
                           onChange={e => setCommentText(e.target.value)}
                           className="flex-1 px-4 py-2 rounded-xl bg-slate-50 border border-slate-100 font-bold text-sm outline-none"
                         />
                         <button onClick={() => handleAddComment(material)} className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-black text-xs">إرسال</button>
                      </div>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}

      {/* Legacy/Other tabs implementation similar to before... */}
      {activeView === 'feed' && <div className="max-w-2xl mx-auto space-y-8">...</div>}
    </div>
  );
};

export default TeacherDashboard;

import React, { useState } from 'react';
import { UserRole, User, SupervisorConfig } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  teachers: User[];
  onForgotPassword: (userId: string) => void;
  supervisorConfig: SupervisorConfig;
  currentYear?: string;
  currentSemester?: string;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, teachers, onForgotPassword, supervisorConfig, currentYear, currentSemester }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [showForgotModal, setShowForgotModal] = useState(false);
  const [forgotId, setForgotId] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال الرقم الوظيفي وكلمة المرور');
      return;
    }

    // Supervisor Login Check
    const isSupervisor = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99');

    if (isSupervisor) {
      const isValidSupervisor = 
        (cleanCode.toUpperCase() === 'S12345' && cleanPass === 'OM12345') || 
        (supervisorConfig.mainPassword && cleanPass === supervisorConfig.mainPassword) ||
        (supervisorConfig.backupPassword && cleanPass === supervisorConfig.backupPassword) ||
        (cleanPass === `${cleanCode}مشرف`);

      if (isValidSupervisor) {
        onLogin({ 
          id: cleanCode, 
          name: `المشرفة (${cleanCode})`, 
          role: UserRole.SUPERVISOR, 
          code: cleanCode,
          isActive: true,
          joinedAt: '2026'
        });
        return;
      } else {
        setError('كلمة مرور المشرفة غير صحيحة');
        return;
      }
    }

    // Teacher & Temp Supervisor Check
    const foundUser = teachers.find(t => t.id === cleanCode);
    if (!foundUser) {
      setError('المستخدم غير مسجل في النظام');
      return;
    }

    if (cleanPass === foundUser.password) {
      onLogin(foundUser);
    } else {
      setError('كلمة المرور غير صحيحة');
    }
  };

  const handleForgotSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (forgotId.trim()) {
      onForgotPassword(forgotId.trim());
      setShowForgotModal(false);
      setForgotId('');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#f8fafc] px-4 font-['Tajawal'] bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
      <div className="max-w-md w-full bg-white/90 backdrop-blur-xl rounded-[2.5rem] shadow-2xl p-10 space-y-8 border border-white relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-emerald-500 via-teal-500 to-blue-500"></div>
        <div className="text-center">
          <div className="mb-6 inline-flex items-center justify-center w-24 h-24 bg-gradient-to-br from-emerald-50 to-teal-50 rounded-[2rem] shadow-inner relative">
             <span className="text-5xl absolute top-4 right-4">📋</span>
             <span className="text-4xl absolute bottom-4 left-4">✒️</span>
          </div>
          <h1 className="text-2xl font-black text-slate-800 mb-2 tracking-tight">منصة الإبداع للمجال الأول</h1>
          <p className="text-slate-500 font-bold text-sm mb-1">بوابة الدخول الموحدة للمجال الأول</p>
          <p className="text-[10px] font-black text-emerald-600 bg-emerald-50 inline-block px-3 py-1 rounded-full">
            {currentYear || '2025-2026'} | {currentSemester || 'الفصل الأول'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 pr-2">الرقم الوظيفي</label>
            <input type="text" required value={code} onChange={(e) => setCode(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-emerald-500 outline-none text-right font-extrabold text-lg transition-all focus:bg-white text-slate-900 placeholder:text-slate-400" placeholder="أدخل الرقم الوظيفي..." />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 pr-2">كلمة المرور</label>
            <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-emerald-500 outline-none text-right font-extrabold text-lg transition-all focus:bg-white text-slate-900 placeholder:text-slate-400" placeholder="••••••••" />
          </div>

          {error && <div className="bg-red-50 text-red-600 text-xs font-black p-4 rounded-2xl text-center animate-pulse">{error}</div>}

          <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg hover:bg-emerald-600 shadow-xl shadow-emerald-100 active:scale-95 transition-all mt-4">تسجيل الدخول</button>
        </form>

        <div className="text-center pt-2">
           <button 
             onClick={() => setShowForgotModal(true)} 
             className="text-xs font-bold text-slate-400 hover:text-emerald-600 transition-colors underline decoration-dotted underline-offset-4"
           >
             نسيت كلمة المرور؟
           </button>
        </div>
      </div>

      {showForgotModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 shadow-2xl animate-slideIn">
              <h3 className="text-xl font-black text-slate-800 mb-2">نسيت كلمة المرور؟</h3>
              <p className="text-slate-500 text-xs font-bold mb-6 leading-relaxed">يرجى إدخال الرقم الوظيفي الخاص بك لإعادة تعيين الحساب.</p>

              <form onSubmit={handleForgotSubmit} className="space-y-4">
                 <input 
                   type="text" 
                   required 
                   placeholder="أدخل الرقم الوظيفي هنا" 
                   value={forgotId}
                   onChange={e => setForgotId(e.target.value)}
                   className="w-full px-5 py-3 rounded-xl bg-slate-50 border border-slate-100 outline-none focus:border-emerald-500 font-black text-lg text-center"
                 />
                 <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-black text-sm shadow-lg hover:bg-emerald-700 transition-all">إرسال الطلب</button>
                 <button type="button" onClick={() => setShowForgotModal(false)} className="w-full text-slate-400 font-bold text-xs py-2">إلغاء</button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default LoginForm;

export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR',
  TEMP_SUPERVISOR = 'TEMP_SUPERVISOR'
}

export interface TempPermissions {
  canViewTeachers: boolean;
  canComment: boolean;
  canApproveProjects: boolean;
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
  mustChangePassword?: boolean;
  isActive: boolean;
  joinedAt: string;
  email?: string;
  phoneNumber?: string;
  subject?: string; // المادة: لغة عربية، إسلامية، دراسات
  teachingGrades?: string; // الصفوف التي تدرسها
  tempPermissions?: TempPermissions; // For Temp Supervisors
}

export interface SupervisorConfig {
  mainPassword?: string;
  backupPassword?: string;
  academicYear?: string; // السنة الدراسية (نص)
  semester?: string; // الفصل الدراسي (نص)
}

export interface Comment {
  id: string;
  authorId: string;
  authorName: string;
  authorRole: UserRole;
  text: string;
  createdAt: string;
  isEdited?: boolean;
}

export interface LessonMaterial {
  id: string;
  teacherId: string;
  teacherName: string;
  lessonTitle: string;
  description: string;
  attachments: Attachment[];
  comments: Comment[];
  createdAt: string;
  academicYear: string;
}

export interface Notification {
  id: string;
  userId: string; // Recipient ID
  message: string;
  isRead: boolean;
  createdAt: string;
  type: 'comment' | 'system';
}

export interface ResetRequest {
  id: string;
  userId: string;
  userName: string;
  requestedAt: string;
  status: 'pending' | 'resolved';
}

export type AttachmentType = 'link' | 'image' | 'video' | 'audio' | 'file';

export interface Attachment {
  type: AttachmentType;
  url: string;
  name: string;
}

export interface Post {
  id: string;
  authorId: string;
  authorName: string;
  title: string;
  content: string;
  attachments: Attachment[];
  isPinned: boolean;
  createdAt: string;
  academicYear: string;
}

export interface ProjectSubmission {
  teacherId: string;
  files: Attachment[];
  notes: string;
  status: 'pending' | 'submitted' | 'approved' | 'needs_work';
  feedback: string;
  badges: string[];
  submittedAt?: string;
}

export interface Project {
  id: string;
  name: string;
  description: string;
  tasks: string[];
  assignedTeacherIds: string[];
  createdAt: string;
  academicYear: string;
  submissions: Record<string, ProjectSubmission>;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Project, Post, ResetRequest, LessonMaterial, Comment, SupervisorConfig, Notification } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const APP_TITLE = "منصة الإبداع للمجال الأول";

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [lessonMaterials, setLessonMaterials] = useState<LessonMaterial[]>(() => {
    const saved = localStorage.getItem('app_lesson_materials');
    return saved ? JSON.parse(saved) : [];
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('app_projects');
    return saved ? JSON.parse(saved) : [];
  });

  const [posts, setPosts] = useState<Post[]>(() => {
    const saved = localStorage.getItem('app_posts');
    return saved ? JSON.parse(saved) : [];
  });

  const [resetRequests, setResetRequests] = useState<ResetRequest[]>(() => {
    const saved = localStorage.getItem('app_reset_requests');
    return saved ? JSON.parse(saved) : [];
  });

  const [notifications, setNotifications] = useState<Notification[]>(() => {
    const saved = localStorage.getItem('app_notifications');
    return saved ? JSON.parse(saved) : [];
  });

  const [supervisorConfig, setSupervisorConfig] = useState<SupervisorConfig>(() => {
    const saved = localStorage.getItem('app_supervisor_config');
    return saved ? JSON.parse(saved) : { 
      mainPassword: '', 
      backupPassword: '', 
      academicYear: '2025-2026', 
      semester: 'الفصل الدراسي الأول' 
    };
  });

  const currentAcademicYear = supervisorConfig.academicYear || "2025-2026";
  const currentSemester = supervisorConfig.semester || "الفصل الأول";

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  useEffect(() => {
    localStorage.setItem('app_lesson_materials', JSON.stringify(lessonMaterials));
  }, [lessonMaterials]);

  useEffect(() => {
    localStorage.setItem('app_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem('app_posts', JSON.stringify(posts));
  }, [posts]);

  useEffect(() => {
    localStorage.setItem('app_reset_requests', JSON.stringify(resetRequests));
  }, [resetRequests]);

  useEffect(() => {
    localStorage.setItem('app_notifications', JSON.stringify(notifications));
  }, [notifications]);

  useEffect(() => {
    localStorage.setItem('app_supervisor_config', JSON.stringify(supervisorConfig));
  }, [supervisorConfig]);

  const handleLogin = (user: User) => {
    if (!user.isActive) {
      alert('عذراً، هذا الحساب غير نشط.');
      return;
    }
    setAuth({ user, isAuthenticated: true });
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setShowChangePassword(true);
    } else {
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const handleUpdateLessonMaterial = (updated: LessonMaterial) => {
    setLessonMaterials(prev => prev.map(m => m.id === updated.id ? updated : m));
  };

  const handleAddNotification = (notification: Notification) => {
    setNotifications(prev => [notification, ...prev]);
  };

  const handleMarkNotificationAsRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const handleResetPassword = (id: string) => {
    const defaultPass = `OM${id}`;
    // Update teacher password in the list
    setTeachers(prev => {
      const newList = prev.map(t => 
        t.id === id ? { ...t, password: defaultPass, mustChangePassword: true } : t
      );
      return newList;
    });
    // Clear the request from pending
    setResetRequests(prev => prev.filter(req => req.userId !== id));
    return defaultPass;
  };

  const handleForgotPasswordRequest = (userId: string) => {
    const teacher = teachers.find(t => t.id === userId && t.isActive);
    if (!teacher) {
      alert('المعلمة غير موجودة أو الحساب معطل.');
      return;
    }
    const newRequest: ResetRequest = {
      id: Date.now().toString(),
      userId: teacher.id,
      userName: teacher.name,
      requestedAt: new Date().toLocaleString('ar-SA'),
      status: 'pending'
    };
    setResetRequests(prev => {
      if (prev.find(r => r.userId === userId)) return prev;
      return [newRequest, ...prev];
    });
    alert('تم إرسال طلب تصفير كلمة المرور للمشرفة.');
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false, password: newPassword } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm 
      onLogin={handleLogin} 
      teachers={teachers} 
      onForgotPassword={handleForgotPasswordRequest}
      supervisorConfig={supervisorConfig}
      currentYear={currentAcademicYear}
      currentSemester={currentSemester}
    />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm 
      onPasswordChanged={handlePasswordChanged} 
      onLogout={handleLogout} 
      currentPassword={auth.user?.password}
    />;
  }

  return (
    <div className="min-h-screen bg-[#f8fafc] font-['Tajawal'] antialiased">
      <nav className="bg-white/90 backdrop-blur-md text-slate-900 shadow-sm sticky top-0 z-[100] border-b border-slate-100 h-20 flex items-center">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="bg-gradient-to-tr from-emerald-600 to-teal-600 p-2.5 rounded-2xl shadow-lg shadow-emerald-100">
                <span className="text-2xl">📋</span>
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black tracking-tight text-slate-900 leading-none mb-1">{APP_TITLE}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                  المجال الأول - {currentAcademicYear} - {currentSemester}
                </span>
              </div>
            </div>
            <div className="flex items-center gap-4 md:gap-6">
              <div className="hidden md:flex flex-col items-end text-left">
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
                <span className="text-[10px] font-bold text-emerald-500 uppercase">
                  {auth.user?.role === UserRole.SUPERVISOR ? 'مشرفة النظام' : 
                   auth.user?.role === UserRole.TEMP_SUPERVISOR ? 'مشرفة مؤقتة' : 'عضو هيئة التدريس'}
                </span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-slate-50 text-slate-600 hover:bg-red-50 hover:text-red-600 px-5 py-2.5 rounded-xl text-xs font-black transition-all active:scale-95 border border-slate-100"
              >
                تسجيل الخروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            posts={posts}
            projects={projects}
            lessonMaterials={lessonMaterials}
            onAddMaterial={(m) => setLessonMaterials(prev => [m, ...prev])}
            onUpdateMaterial={handleUpdateLessonMaterial}
            updateProjectSubmission={(pid, sub) => {
               setProjects(prev => prev.map(p => p.id === pid ? { ...p, submissions: { ...p.submissions, [sub.teacherId]: sub } } : p));
            }}
            currentYear={currentAcademicYear}
            notifications={notifications.filter(n => n.userId === auth.user?.id)}
            onMarkAsRead={handleMarkNotificationAsRead}
          />
        ) : (
          <SupervisorDashboard 
            user={auth.user}
            teachers={teachers}
            posts={posts}
            projects={projects}
            lessonMaterials={lessonMaterials}
            resetRequests={resetRequests}
            onAddPost={(p) => setPosts(prev => [p, ...prev])}
            onDeletePost={(id) => setPosts(prev => prev.filter(p => p.id !== id))}
            onTogglePinPost={(id) => setPosts(prev => prev.map(p => p.id === id ? { ...p, isPinned: !p.isPinned } : p))}
            onAddTeacher={(id, name, email, phone, subject, grades) => {
              const defaultPass = `OM${id}`;
              const newTeacher: User = { 
                id, 
                code: id, 
                name, 
                role: UserRole.TEACHER, 
                password: defaultPass, 
                mustChangePassword: true, 
                isActive: true, 
                joinedAt: currentAcademicYear, 
                email, 
                phoneNumber: phone,
                subject,
                teachingGrades: grades
              };
              setTeachers(prev => [...prev, newTeacher]);
            }}
            onSoftDeleteTeacher={(id) => setTeachers(prev => prev.map(t => t.id === id ? { ...t, isActive: false } : t))}
            onResetPassword={handleResetPassword}
            onAddProject={(p) => setProjects(prev => [p, ...prev])}
            onDeleteProject={(id) => setProjects(prev => prev.filter(p => p.id !== id))}
            onUpdateProjectSubmission={(pid, sub) => {
               setProjects(prev => prev.map(p => p.id === pid ? { ...p, submissions: { ...p.submissions, [sub.teacherId]: sub } } : p));
            }}
            onAddTempSupervisor={(u) => setTeachers(prev => [...prev, u])}
            onUpdateSecurity={(newConfig) => setSupervisorConfig(prev => ({ ...prev, ...newConfig }))}
            onUpdateLessonMaterial={handleUpdateLessonMaterial}
            onAddNotification={handleAddNotification}
            supervisorConfig={supervisorConfig}
            academicYear={currentAcademicYear}
            semester={currentSemester}
          />
        )}
      </main>

      <footer className="py-8 text-center text-slate-400 text-[10px] font-bold border-t border-slate-100 mt-12 bg-white/50">
        جميع الحقوق محفوظة - {APP_TITLE} © {currentAcademicYear}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { User, Project, Post, ProjectSubmission, Attachment, ResetRequest, LessonMaterial, Comment, UserRole, SupervisorConfig, Notification } from '../types';

interface SupervisorDashboardProps {
  user: User;
  teachers: User[];
  posts: Post[];
  projects: Project[];
  lessonMaterials: LessonMaterial[];
  resetRequests: ResetRequest[];
  onAddPost: (post: Post) => void;
  onDeletePost: (id: string) => void;
  onTogglePinPost: (id: string) => void;
  onAddTeacher: (id: string, name: string, email?: string, phone?: string, subject?: string, grades?: string) => void;
  onSoftDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (project: Project) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
  onAddTempSupervisor: (user: User) => void;
  onUpdateSecurity: (config: SupervisorConfig) => void;
  onUpdateLessonMaterial: (material: LessonMaterial) => void;
  onAddNotification: (notification: Notification) => void;
  supervisorConfig: SupervisorConfig;
  academicYear: string;
  semester: string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  user, teachers, posts, projects, lessonMaterials, resetRequests,
  onAddPost, onDeletePost, onTogglePinPost,
  onAddTeacher, onSoftDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateProjectSubmission,
  onAddTempSupervisor, onUpdateSecurity, onUpdateLessonMaterial, onAddNotification,
  supervisorConfig, academicYear, semester
}) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'projects' | 'lessons' | 'teachers' | 'team'>('feed');

  // Security & Config State
  const [newBackupPass, setNewBackupPass] = useState(supervisorConfig.backupPassword || '');
  const [newMainPass, setNewMainPass] = useState(supervisorConfig.mainPassword || '');
  const [editYear, setEditYear] = useState(academicYear);
  const [editSemester, setEditSemester] = useState(semester);

  // Comment State
  const [commentText, setCommentText] = useState<Record<string, string>>({});
  const [editingCommentId, setEditingCommentId] = useState<string | null>(null);
  const [editCommentText, setEditCommentText] = useState('');

  // Add Teacher State
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [newTeacherPhone, setNewTeacherPhone] = useState('');
  const [newTeacherSubject, setNewTeacherSubject] = useState('لغة عربية');
  const [newTeacherGrades, setNewTeacherGrades] = useState('');

  // Temp Supervisor Form
  const [tempName, setTempName] = useState('');
  const [tempId, setTempId] = useState('');
  const [tempPermissions, setTempPermissions] = useState({ canViewTeachers: true, canComment: true, canApproveProjects: false });

  // Reset Success State
  const [resetResult, setResetResult] = useState<{ name: string, pass: string, phone?: string } | null>(null);

  const handleAddComment = (material: LessonMaterial) => {
    const text = commentText[material.id];
    if (!text?.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      authorId: user.id,
      authorName: user.name,
      authorRole: user.role,
      text: text,
      createdAt: new Date().toLocaleString('ar-SA')
    };
    onUpdateLessonMaterial({ ...material, comments: [...material.comments, newComment] });

    // Add Notification for the teacher
    if (material.teacherId !== user.id) {
       onAddNotification({
         id: Date.now().toString(),
         userId: material.teacherId,
         message: `قام ${user.name} بإضافة تعليق جديد على درسك: ${material.lessonTitle}`,
         isRead: false,
         createdAt: new Date().toLocaleString('ar-SA'),
         type: 'comment'
       });
    }

    setCommentText(prev => ({ ...prev, [material.id]: '' }));
  };

  const handleEditComment = (material: LessonMaterial, commentId: string) => {
    const updatedComments = material.comments.map(c => 
      c.id === commentId ? { ...c, text: editCommentText, isEdited: true } : c
    );
    onUpdateLessonMaterial({ ...material, comments: updatedComments });
    setEditingCommentId(null);
    setEditCommentText('');
  };

  const handleCreateTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTeacherName || !newTeacherId) return alert('يرجى تعبئة الحقول الإجبارية');
    onAddTeacher(newTeacherId, newTeacherName, undefined, newTeacherPhone, newTeacherSubject, newTeacherGrades);
    setNewTeacherName('');
    setNewTeacherId('');
    setNewTeacherPhone('');
    setNewTeacherGrades('');
    alert('تم إضافة المعلمة بنجاح');
  };

  const handleCreateTempSupervisor = (e: React.FormEvent) => {
    e.preventDefault();
    if (!tempName || !tempId) return;
    const newUser: User = {
      id: tempId,
      code: tempId,
      name: tempName,
      role: UserRole.TEMP_SUPERVISOR,
      password: `TEMP${tempId}`,
      isActive: true,
      joinedAt: academicYear,
      tempPermissions: tempPermissions
    };
    onAddTempSupervisor(newUser);
    setTempName('');
    setTempId('');
    alert('تمت إضافة المشرف المؤقت بنجاح');
  };

  const handleSaveConfig = () => {
     onUpdateSecurity({
        backupPassword: newBackupPass,
        mainPassword: newMainPass,
        academicYear: editYear,
        semester: editSemester
     });
     alert('تم حفظ الإعدادات بنجاح');
  };

  const handleResetTeacherAction = (teacherId: string, teacherName: string) => {
    if (window.confirm(`هل أنتِ متأكدة من إعادة تعيين كلمة المرور للمعلمة ${teacherName}؟`)) {
      const newPass = onResetPassword(teacherId);
      const teacher = teachers.find(t => t.id === teacherId);
      setResetResult({ name: teacherName, pass: newPass, phone: teacher?.phoneNumber });
    }
  };

  const copyToClipboard = (text: string) => {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(text).then(() => {
        alert('✅ تم نسخ كلمة المرور بنجاح');
      }).catch(err => {
        console.error('Copy failed', err);
        alert('فشل النسخ التلقائي');
      });
    } else {
      const textArea = document.createElement("textarea");
      textArea.value = text;
      document.body.appendChild(textArea);
      textArea.select();
      document.execCommand('copy');
      document.body.removeChild(textArea);
      alert('✅ تم نسخ كلمة المرور بنجاح');
    }
  };

  const sendToWhatsApp = (phone: string, name: string, pass: string) => {
    const cleanPhone = phone.replace(/\D/g, '');
    const message = `السلام عليكم أ. ${name}%0Aتم إعادة تعيين كلمة المرور الخاصة بكِ في منصة الإبداع للمجال الأول.%0Aكلمة المرور الجديدة هي: ${pass}%0A%0Aيرجى تسجيل الدخول وتغييرها فوراً لضمان الأمان.`;
    window.open(`https://wa.me/${cleanPhone}?text=${message}`, '_blank');
  };

  const getFileIcon = (type: string, name: string) => {
    if (type === 'link') return '🔗';
    if (type === 'video') return '🎥';
    if (type === 'audio') return '🎙️';
    if (type === 'image') return '🖼️';
    return '📄';
  };

  const activeTeachers = useMemo(() => teachers.filter(t => t.isActive && t.role === UserRole.TEACHER), [teachers]);
  const pendingResets = useMemo(() => resetRequests.filter(r => r.status === 'pending'), [resetRequests]);

  return (
    <div className="space-y-8 pb-20 animate-fadeIn">
      {/* Reset Result Modal */}
      {resetResult && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[300] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl animate-slideIn text-center border-t-[12px] border-emerald-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-6 shadow-inner">✓</div>
            <h3 className="text-2xl font-black text-slate-900 mb-2">تم التصفير بنجاح</h3>
            <p className="text-slate-500 text-sm font-bold mb-8">المعلمة: <span className="text-slate-900">{resetResult.name}</span></p>

            <div className="bg-slate-50 p-8 rounded-[2rem] border-2 border-dashed border-slate-200 mb-8 relative group">
               <span className="text-[10px] font-black text-slate-400 absolute top-3 right-6 tracking-widest uppercase">كلمة المرور الجديدة</span>
               <div className="text-3xl font-black text-emerald-600 tracking-widest font-mono">{resetResult.pass}</div>
            </div>

            <div className="grid grid-cols-1 gap-4">
              <button 
                onClick={() => copyToClipboard(resetResult.pass)} 
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-sm shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-3 active:scale-95"
              >
                <span className="text-lg">📋</span> نسخ كلمة المرور
              </button>

              {resetResult.phone ? (
                <button 
                  onClick={() => sendToWhatsApp(resetResult.phone!, resetResult.name, resetResult.pass)} 
                  className="w-full bg-[#25D366] text-white py-4 rounded-2xl font-black text-sm shadow-xl hover:opacity-90 transition-all flex items-center justify-center gap-3 active:scale-95"
                >
                  <span className="text-lg">📱</span> إرسال عبر واتساب
                </button>
              ) : (
                <div className="text-[10px] text-amber-500 font-bold bg-amber-50 p-2 rounded-lg">يرجى ملاحظة: رقم الهاتف غير مسجل لإرسال الواتساب تلقائياً</div>
              )}

              <button 
                onClick={() => setResetResult(null)} 
                className="w-full text-slate-400 font-bold text-xs py-2 hover:text-slate-600 transition-colors"
              >
                إغلاق النافذة
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Navigation Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-4xl overflow-x-auto custom-scrollbar">
          {[
            { id: 'feed', label: '📢 التواصل', icon: '📢' },
            { id: 'lessons', label: '🎨 ركن الإبداع', icon: '🎨' },
            { id: 'projects', label: '🚀 المشاريع', icon: '🚀' },
            { id: 'teachers', label: '👥 المعلمات', icon: '👥' },
            { id: 'team', label: '⚙️ الفريق والأمان', icon: '⚙️' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[120px] px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                activeTab === tab.id ? `bg-emerald-600 text-white shadow-lg` : `text-slate-500 hover:bg-emerald-50`
              }`}
            >
              <span>{tab.icon}</span>
              <span>{tab.label}</span>
              {tab.id === 'teachers' && pendingResets.length > 0 && (
                <span className="bg-red-500 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center animate-pulse shadow-sm">!</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'lessons' && (
        <div className="space-y-8 animate-fadeIn">
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <h3 className="text-2xl font-black text-slate-900">ركن الإبداع الدرسي</h3>
              <p className="text-slate-400 font-bold text-sm">متابعة المواد العلمية المرفوعة من المعلمات للعام {academicYear}</p>
           </div>
           {/* ... existing lesson rendering ... */}
           <div className="grid grid-cols-1 gap-6">
              {lessonMaterials.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-slate-200 font-bold text-slate-300">لا توجد مواد مرفوعة حالياً</div>
              ) : (
                lessonMaterials.map(material => (
                  <div key={material.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 transition-all hover:shadow-md">
                     <div className="flex justify-between items-start mb-4">
                        <div>
                           <h4 className="text-xl font-black text-slate-900">{material.lessonTitle}</h4>
                           <span className="text-xs font-bold text-emerald-600">بواسطة: {material.teacherName}</span>
                        </div>
                        <span className="text-[10px] text-slate-400 font-bold">{material.createdAt}</span>
                     </div>
                     <p className="text-slate-600 font-bold text-sm mb-6 bg-slate-50 p-5 rounded-2xl border border-slate-100">{material.description}</p>

                     <div className="flex flex-wrap gap-3 mb-8">
                        {material.attachments.map((att, i) => (
                          <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-indigo-50 px-5 py-3 rounded-2xl border border-indigo-100 text-xs font-black text-indigo-700 hover:bg-indigo-100 transition-colors">
                             {getFileIcon(att.type, att.name)} {att.name} <span className="opacity-40 pr-1">📥</span>
                          </a>
                        ))}
                     </div>

                     <div className="border-t border-slate-100 pt-6 space-y-4">
                        <h5 className="font-black text-slate-700 text-sm">سجل النقاش والتوجيه والإثراء:</h5>
                        <div className="space-y-3">
                           {material.comments.map(c => (
                             <div key={c.id} className={`p-5 rounded-[2rem] text-sm ${c.authorRole === UserRole.TEACHER ? 'bg-indigo-50/50 mr-8 border-r-4 border-indigo-400' : 'bg-emerald-50/50 ml-8 border-r-4 border-emerald-400'}`}>
                                <div className="flex justify-between mb-1">
                                   <div className="flex items-center gap-2">
                                      <span className="font-black text-slate-800">{c.authorName}</span>
                                      {c.isEdited && <span className="text-[8px] font-bold text-slate-400 italic">(معدل)</span>}
                                   </div>
                                   <div className="flex items-center gap-2">
                                      <span className="text-[10px] text-slate-400 font-bold">{c.createdAt}</span>
                                      {c.authorId === user.id && (
                                        <button onClick={() => { setEditingCommentId(c.id); setEditCommentText(c.text); }} className="text-slate-300 hover:text-emerald-600 transition-colors">✏️</button>
                                      )}
                                   </div>
                                </div>
                                {editingCommentId === c.id ? (
                                  <div className="space-y-2 mt-2">
                                     <textarea value={editCommentText} onChange={e => setEditCommentText(e.target.value)} className="w-full p-3 border rounded-2xl text-xs font-bold outline-none focus:border-emerald-500" rows={2} />
                                     <div className="flex gap-2">
                                        <button onClick={() => handleEditComment(material, c.id)} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-[10px] font-black shadow-md">تحديث</button>
                                        <button onClick={() => setEditingCommentId(null)} className="bg-slate-200 text-slate-500 px-4 py-2 rounded-xl text-[10px] font-black">إلغاء</button>
                                     </div>
                                  </div>
                                ) : (
                                  <p className="font-bold text-slate-600 leading-relaxed">{c.text}</p>
                                )}
                             </div>
                           ))}
                        </div>
                        <div className="flex gap-2 bg-slate-50 p-2 rounded-2xl border border-slate-100 mt-4">
                           <input 
                             type="text" 
                             placeholder="أضف توجيهاً أو تعليقاً للمعلمة..." 
                             value={commentText[material.id] || ''} 
                             onChange={e => setCommentText({...commentText, [material.id]: e.target.value})}
                             className="flex-1 px-5 py-3 rounded-xl bg-white border border-slate-100 font-bold text-sm outline-none focus:border-emerald-500 transition-all"
                           />
                           <button onClick={() => handleAddComment(material)} className="bg-emerald-600 text-white px-8 py-3 rounded-xl font-black text-xs shadow-lg hover:bg-emerald-700 transition-all active:scale-95">إرسال</button>
                        </div>
                     </div>
                  </div>
                ))
              )}
           </div>
        </div>
      )}

      {activeTab === 'teachers' && (
        <div className="space-y-8 animate-fadeIn">
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
             <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                <div>
                  <h3 className="text-2xl font-black text-slate-900">سجل الكادر التعليمي</h3>
                  <p className="text-slate-400 font-bold text-sm">إدارة الحسابات وكلمات المرور</p>
                </div>
             </div>

              {/* Add Teacher Form */}
              <div className="mt-8 pt-8 border-t border-slate-100">
                <h4 className="font-black text-slate-800 mb-4 text-sm">➕ إضافة معلمة جديدة</h4>
                <form onSubmit={handleCreateTeacher} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-3">
                  <input type="text" placeholder="الاسم الكامل" value={newTeacherName} onChange={e => setNewTeacherName(e.target.value)} className="px-4 py-3 rounded-xl bg-slate-50 border font-bold text-xs" />
                  <input type="text" placeholder="الرقم الوظيفي" value={newTeacherId} onChange={e => setNewTeacherId(e.target.value)} className="px-4 py-3 rounded-xl bg-slate-50 border font-bold text-xs" />
                  <input type="text" placeholder="رقم الهاتف (للواتساب)" value={newTeacherPhone} onChange={e => setNewTeacherPhone(e.target.value)} className="px-4 py-3 rounded-xl bg-slate-50 border font-bold text-xs" />

                  <select value={newTeacherSubject} onChange={e => setNewTeacherSubject(e.target.value)} className="px-4 py-3 rounded-xl bg-slate-50 border font-bold text-xs">
                     <option value="لغة عربية">لغة عربية</option>
                     <option value="تربية إسلامية">تربية إسلامية</option>
                     <option value="دراسات اجتماعية">دراسات اجتماعية</option>
                  </select>

                  <input type="text" placeholder="الصفوف (مثال: 1، 2)" value={newTeacherGrades} onChange={e => setNewTeacherGrades(e.target.value)} className="px-4 py-3 rounded-xl bg-slate-50 border font-bold text-xs" />

                  <button type="submit" className="lg:col-span-5 bg-indigo-600 text-white py-3 rounded-xl font-black shadow-lg text-xs hover:bg-indigo-700 transition-all">حفظ وإضافة المعلمة</button>
