import { User, Project, Post, Attachment, ProjectSubmission, AttachmentType, LessonMaterial, Comment, UserRole, Notification } from '../types';

interface TeacherDashboardProps {
  user: User;
  posts: Post[];
  projects: Project[];
  lessonMaterials: LessonMaterial[];
  onAddMaterial: (material: LessonMaterial) => void;
  onUpdateMaterial: (material: LessonMaterial) => void;
  updateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
  currentYear: string;
  notifications: Notification[];
  onMarkAsRead: (id: string) => void;
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ 
  user, posts, projects, lessonMaterials, onAddMaterial, onUpdateMaterial, updateProjectSubmission, currentYear, notifications, onMarkAsRead
}) => {
  const [activeView, setActiveView] = useState<'feed' | 'my-projects' | 'lessons' | 'badges' | 'notifications'>('feed');
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
  const [selectedMaterialId, setSelectedMaterialId] = useState<string | null>(null);

  // Material Form State
  const [newLessonTitle, setNewLessonTitle] = useState('');
  const [newLessonDesc, setNewLessonDesc] = useState('');
  const [materialFiles, setMaterialFiles] = useState<Attachment[]>([]);
  const [commentText, setCommentText] = useState('');

  const myMaterials = lessonMaterials.filter(m => m.teacherId === user.id);
  const unreadCount = notifications.filter(n => !n.isRead).length;

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'material' | 'project') => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      let type: AttachmentType = 'file';
      if (file.type.startsWith('image')) type = 'image';
      else if (file.type.startsWith('video')) type = 'video';
      else if (file.type.startsWith('audio')) type = 'audio';

      reader.onload = () => {
        const newAtt = { type, url: reader.result as string, name: file.name };
        if (target === 'material') setMaterialFiles(prev => [...prev, newAtt]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveMaterial = () => {
    if (!newLessonTitle) return alert('يرجى إدخال عنوان الدرس');
    const material: LessonMaterial = {
      id: Date.now().toString(),
      teacherId: user.id,
      teacherName: user.name,
      lessonTitle: newLessonTitle,
      description: newLessonDesc,
      attachments: materialFiles,
      comments: [],
      createdAt: new Date().toLocaleDateString('ar-SA'),
      academicYear: currentYear
    };
    onAddMaterial(material);
    setNewLessonTitle('');
    setNewLessonDesc('');
    setMaterialFiles([]);
    alert('تمت إضافة مادة الدرس بنجاح');
  };

  const handleAddComment = (material: LessonMaterial) => {
    if (!commentText.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      authorId: user.id,
      authorName: user.name,
      authorRole: UserRole.TEACHER,
      text: commentText,
      createdAt: new Date().toLocaleString('ar-SA')
    };
    onUpdateMaterial({ ...material, comments: [...material.comments, newComment] });
    setCommentText('');
  };

  const getFileIcon = (type: string, name: string) => {
    if (type === 'link') return '🔗';
    if (type === 'video') return '🎥';
    if (type === 'audio') return '🎙️';
    if (type === 'image') return '🖼️';
    return '📄';
  };

  return (
    <div className="pb-24 animate-fadeIn">
      <div className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-100 p-4 z-50 flex justify-around md:static md:bg-transparent md:border-0 md:p-0 md:justify-center md:mb-10">
         <div className="bg-white p-1.5 md:p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-2xl">
            {[
              { id: 'feed', icon: '📢', label: 'الرئيسية' },
              { id: 'lessons', icon: '🎨', label: 'إبداع درسي' },
              { id: 'my-projects', icon: '🚀', label: 'مشاريعي' },
              { id: 'badges', icon: '🏆', label: 'أوسمتي' },
              { id: 'notifications', icon: '🔔', label: 'التنبيهات', count: unreadCount }
            ].map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveView(item.id as any); setSelectedProjectId(null); setSelectedMaterialId(null); }}
                className={`flex-1 px-4 py-3 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm relative ${
                  activeView === item.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <span>{item.icon}</span>
                <span className="hidden sm:inline">{item.label}</span>
                {item.count ? (
                    <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[9px] w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">{item.count}</span>
                ) : null}
              </button>
            ))}
         </div>
      </div>

      {activeView === 'notifications' && (
        <div className="max-w-2xl mx-auto space-y-6">
            <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 mb-6">
                <h3 className="text-2xl font-black text-slate-800">التنبيهات والإشعارات</h3>
                <p className="text-slate-400 font-bold text-sm">آخر التحديثات والتعليقات الواردة من المشرفة</p>
            </div>

            {notifications.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-slate-200 font-bold text-slate-300">لا توجد تنبيهات جديدة</div>
            ) : (
                <div className="space-y-4">
                    {notifications.map(notif => (
                        <div 
                            key={notif.id} 
                            onClick={() => onMarkAsRead(notif.id)}
                            className={`p-6 rounded-[2rem] border transition-all cursor-pointer ${notif.isRead ? 'bg-white border-slate-100 opacity-70' : 'bg-indigo-50 border-indigo-100 shadow-md'}`}
                        >
                            <div className="flex justify-between items-start mb-2">
                                <span className={`text-xs font-black ${notif.isRead ? 'text-slate-400' : 'text-indigo-600'}`}>
                                    {notif.isRead ? 'مقرؤة' : '• جديدة'}
                                </span>
                                <span className="text-[10px] text-slate-400 font-bold">{notif.createdAt}</span>
                            </div>
                            <p className="text-slate-800 font-bold text-sm">{notif.message}</p>
                        </div>
                    ))}
                </div>
            )}
        </div>
      )}

      {activeView === 'lessons' && (
        <div className="max-w-4xl mx-auto space-y-8">
           <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
              <h3 className="text-2xl font-black text-slate-800 mb-6">إضافة مادة درسية جديدة</h3>
              <div className="space-y-4">
                 <input 
                   type="text" 
                   placeholder="عنوان الدرس" 
                   value={newLessonTitle} 
                   onChange={e => setNewLessonTitle(e.target.value)}
                   className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-400 outline-none font-bold text-slate-900"
                 />
                 <textarea 
                   placeholder="وصف موجز للدرس..." 
                   value={newLessonDesc} 
                   onChange={e => setNewLessonDesc(e.target.value)}
                   className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-400 outline-none font-bold text-slate-900 min-h-[100px]"
                 />
                 <div className="flex gap-4">
                   <label className="flex-1 cursor-pointer bg-indigo-50 text-indigo-600 px-6 py-4 rounded-2xl font-black text-center border-2 border-dashed border-indigo-200">
                      + إضافة مرفقات (PPT, PDF, Video, Image)
                      <input type="file" onChange={e => handleFileUpload(e, 'material')} className="hidden" />
                   </label>
                 </div>
                 {materialFiles.length > 0 && (
                   <div className="flex flex-wrap gap-2">
                     {materialFiles.map((f, i) => (
                       <span key={i} className="bg-slate-100 px-3 py-1 rounded-lg text-xs font-bold">{getFileIcon(f.type, f.name)} {f.name}</span>
                     ))}
                   </div>
                 )}
                 <button onClick={handleSaveMaterial} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg">حفظ المادة الدراسية</button>
              </div>
           </div>

           <div className="grid grid-cols-1 gap-6">
              {myMaterials.map(material => (
                <div key={material.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                   <div className="flex justify-between items-start mb-4">
                      <h4 className="text-xl font-black text-slate-900">{material.lessonTitle}</h4>
                      <span className="text-[10px] text-slate-400 font-bold">{material.createdAt}</span>
                   </div>
                   <p className="text-slate-600 font-bold text-sm mb-6">{material.description}</p>

                   <div className="flex flex-wrap gap-3 mb-6">
                      {material.attachments.map((att, i) => (
                        <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-xl border border-slate-100 text-xs font-black text-indigo-600 hover:bg-indigo-50">
                           {getFileIcon(att.type, att.name)} {att.name}
                        </a>
                      ))}
                   </div>

                   <div className="border-t border-slate-100 pt-6 space-y-4">
                      <h5 className="font-black text-slate-700 text-sm">التواصل مع المشرفة ({material.comments.length}):</h5>
                      <div className="space-y-3">
                         {material.comments.map(c => (
                           <div key={c.id} className={`p-4 rounded-2xl text-sm ${c.authorRole === UserRole.TEACHER ? 'bg-indigo-50 mr-8' : 'bg-emerald-50 ml-8 border-r-4 border-emerald-400'}`}>
                              <div className="flex justify-between mb-1">
                                 <span className="font-black text-slate-800">{c.authorName}</span>
                                 <span className="text-[10px] text-slate-400">{c.createdAt}</span>
                              </div>
                              <p className="font-bold text-slate-600">{c.text}</p>
                           </div>
                         ))}
                      </div>
                      <div className="flex gap-2">
                         <input 
                           type="text" 
                           placeholder="أكتبي رداً أو استفساراً..." 
                           value={commentText} 
                           onChange={e => setCommentText(e.target.value)}
                           className="flex-1 px-4 py-2 rounded-xl bg-slate-50 border border-slate-100 font-bold text-sm text-slate-900 outline-none"
                         />
                         <button onClick={() => handleAddComment(material)} className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-black text-xs">إرسال</button>
                      </div>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}

      {/* Legacy/Other tabs implementation similar to before... */}
      {activeView === 'feed' && <div className="max-w-2xl mx-auto space-y-8"></div>}
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useMemo } from 'react';
import { User, Project, Post, ProjectSubmission, Attachment, ResetRequest, LessonMaterial, Comment, UserRole, SupervisorConfig, Notification } from '../types';

interface SupervisorDashboardProps {
  user: User;
  teachers: User[];
  posts: Post[];
  projects: Project[];
  lessonMaterials: LessonMaterial[];
  resetRequests: ResetRequest[];
  onAddPost: (post: Post) => void;
  onDeletePost: (id: string) => void;
  onTogglePinPost: (id: string) => void;
  onAddTeacher: (id: string, name: string, email?: string, phone?: string, subject?: string, grades?: string) => void;
  onSoftDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (project: Project) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
  onAddTempSupervisor: (user: User) => void;
  onUpdateSecurity: (config: SupervisorConfig) => void;
  onUpdateLessonMaterial: (material: LessonMaterial) => void;
  onAddNotification: (notification: Notification) => void;
  supervisorConfig: SupervisorConfig;
  academicYear: string;
  semester: string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  user, teachers, posts, projects, lessonMaterials, resetRequests,
  onAddPost, onDeletePost, onTogglePinPost,
  onAddTeacher, onSoftDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateProjectSubmission,
  onAddTempSupervisor, onUpdateSecurity, onUpdateLessonMaterial, onAddNotification,
  supervisorConfig, academicYear, semester
}) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'projects' | 'lessons' | 'teachers' | 'team'>('feed');

  // Security & Config State
  const [newBackupPass, setNewBackupPass] = useState(supervisorConfig.backupPassword || '');
  const [newMainPass, setNewMainPass] = useState(supervisorConfig.mainPassword || '');
  const [editYear, setEditYear] = useState(academicYear);
  const [editSemester, setEditSemester] = useState(semester);

  // Comment State
  const [commentText, setCommentText] = useState<Record<string, string>>({});
  const [editingCommentId, setEditingCommentId] = useState<string | null>(null);
  const [editCommentText, setEditCommentText] = useState('');

  // Add Teacher State
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [newTeacherPhone, setNewTeacherPhone] = useState('');
  const [newTeacherSubject, setNewTeacherSubject] = useState('لغة عربية');
  const [newTeacherGrades, setNewTeacherGrades] = useState('');

  // Temp Supervisor Form
  const [tempName, setTempName] = useState('');
  const [tempId, setTempId] = useState('');
  const [tempPermissions, setTempPermissions] = useState({ 
    canViewTeachers: true, 
    canComment: true, 
    canApproveProjects: false,
    canManageUsers: false
  });
  const [tempAllowedSubjects, setTempAllowedSubjects] = useState<string[]>([]);

  // Reset Success State
  const [resetResult, setResetResult] = useState<{ name: string, pass: string, phone?: string } | null>(null);

  const isMainSupervisor = user.role === UserRole.SUPERVISOR;
  const isTempSupervisor = user.role === UserRole.TEMP_SUPERVISOR;

  // --- Filtering Logic based on Permissions ---

  const availableSubjects = ['لغة عربية', 'تربية إسلامية', 'دراسات اجتماعية'];

  // 1. Filter Teachers
  const filteredTeachers = useMemo(() => {
    let list = teachers.filter(t => t.isActive && t.role === UserRole.TEACHER);

    if (isTempSupervisor && user.tempPermissions?.allowedSubjects) {
      const allowed = user.tempPermissions.allowedSubjects;
      if (allowed.length > 0) {
        list = list.filter(t => t.subject && allowed.includes(t.subject));
      }
    }
    return list;
  }, [teachers, isTempSupervisor, user.tempPermissions]);

  // 2. Filter Lessons
  const filteredLessons = useMemo(() => {
    if (isMainSupervisor) return lessonMaterials;

    // For temp supervisors, get IDs of teachers they are allowed to see
    const allowedTeacherIds = filteredTeachers.map(t => t.id);
    return lessonMaterials.filter(m => allowedTeacherIds.includes(m.teacherId));
  }, [lessonMaterials, filteredTeachers, isMainSupervisor]);

  // 3. Filter Projects (based on assigned teachers)
  // Logic: Show project if AT LEAST ONE assigned teacher is in the allowed list
  // Or simply show all projects but restrict approval actions? Let's filter visibility for cleaner UI.
  const filteredProjects = useMemo(() => {
      if (isMainSupervisor) return projects;
      const allowedTeacherIds = filteredTeachers.map(t => t.id);
      return projects.filter(p => p.assignedTeacherIds.some(id => allowedTeacherIds.includes(id)));
  }, [projects, filteredTeachers, isMainSupervisor]);

  // --------------------------------------------

  const handleAddComment = (material: LessonMaterial) => {
    if (isTempSupervisor && !user.tempPermissions?.canComment) {
        alert('ليس لديك صلاحية التعليق.');
        return;
    }

    const text = commentText[material.id];
    if (!text?.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      authorId: user.id,
      authorName: user.name,
      authorRole: user.role,
      text: text,
      createdAt: new Date().toLocaleString('ar-SA')
    };
    onUpdateLessonMaterial({ ...material, comments: [...material.comments, newComment] });

    // Add Notification for the teacher
    if (material.teacherId !== user.id) {
       onAddNotification({
         id: Date.now().toString(),
         userId: material.teacherId,
         message: `قام ${user.name} بإضافة تعليق جديد على درسك: ${material.lessonTitle}`,
         isRead: false,
         createdAt: new Date().toLocaleString('ar-SA'),
         type: 'comment'
       });
    }

    setCommentText(prev => ({ ...prev, [material.id]: '' }));
  };

  const handleEditComment = (material: LessonMaterial, commentId: string) => {
    const updatedComments = material.comments.map(c => 
      c.id === commentId ? { ...c, text: editCommentText, isEdited: true } : c
    );
    onUpdateLessonMaterial({ ...material, comments: updatedComments });
    setEditingCommentId(null);
    setEditCommentText('');
  };

  const handleCreateTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (isTempSupervisor && !user.tempPermissions?.canManageUsers) return alert('ليس لديك صلاحية إضافة معلمات.');

    if (!newTeacherName || !newTeacherId) return alert('يرجى تعبئة الحقول الإجبارية');
    onAddTeacher(newTeacherId, newTeacherName, undefined, newTeacherPhone, newTeacherSubject, newTeacherGrades);
    setNewTeacherName('');
    setNewTeacherId('');
    setNewTeacherPhone('');
    setNewTeacherGrades('');
    alert('تم إضافة المعلمة بنجاح');
  };

  const handleCreateTempSupervisor = (e: React.FormEvent) => {
    e.preventDefault();
    if (!tempName || !tempId) return;

    const newUser: User = {
      id: tempId,
      code: tempId,
      name: tempName,
      role: UserRole.TEMP_SUPERVISOR,
      password: `TEMP${tempId}`,
      isActive: true,
      joinedAt: academicYear,
      tempPermissions: {
        ...tempPermissions,
        allowedSubjects: tempAllowedSubjects
      }
    };
    onAddTempSupervisor(newUser);
    setTempName('');
    setTempId('');
    setTempAllowedSubjects([]);
    alert('تمت إضافة المشرف المؤقت بنجاح');
  };

  const toggleSubjectPermission = (subject: string) => {
      setTempAllowedSubjects(prev => 
        prev.includes(subject) ? prev.filter(s => s !== subject) : [...prev, subject]
      );
  };

  const handleSaveConfig = () => {
     onUpdateSecurity({
        backupPassword: newBackupPass,
        mainPassword: newMainPass,
        academicYear: editYear,
        semester: editSemester
     });
     alert('تم حفظ الإعدادات بنجاح');
  };

  const handleResetTeacherAction = (teacherId: string, teacherName: string) => {
    if (isTempSupervisor && !user.tempPermissions?.canManageUsers) return alert('ليس لديك صلاحية إعادة تعيين كلمات المرور.');

    if (window.confirm(`هل أنتِ متأكدة من إعادة تعيين كلمة المرور للمعلمة ${teacherName}؟`)) {
      const newPass = onResetPassword(teacherId);
      const teacher = teachers.find(t => t.id === teacherId);
      setResetResult({ name: teacherName, pass: newPass, phone: teacher?.phoneNumber });
    }
  };

  const copyToClipboard = (text: string) => {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(text).then(() => {
        alert('✅ تم نسخ كلمة المرور بنجاح');
      }).catch(err => {
        console.error('Copy failed', err);
        alert('فشل النسخ التلقائي');
      });
    } else {
      const textArea = document.createElement("textarea");
      textArea.value = text;
      document.body.appendChild(textArea);
      textArea.select();
      document.execCommand('copy');
      document.body.removeChild(textArea);
      alert('✅ تم نسخ كلمة المرور بنجاح');
    }
  };

  const sendToWhatsApp = (phone: string, name: string, pass: string) => {
    const cleanPhone = phone.replace(/\D/g, '');
    const message = `السلام عليكم أ. ${name}%0Aتم إعادة تعيين كلمة المرور الخاصة بكِ في منصة الإبداع للمجال الأول.%0Aكلمة المرور الجديدة هي: ${pass}%0A%0Aيرجى تسجيل الدخول وتغييرها فوراً لضمان الأمان.`;
    window.open(`https://wa.me/${cleanPhone}?text=${message}`, '_blank');
  };

  const getFileIcon = (type: string, name: string) => {
    if (type === 'link') return '🔗';
    if (type === 'video') return '🎥';
    if (type === 'audio') return '🎙️';
    if (type === 'image') return '🖼️';
    return '📄';
  };

  const pendingResets = useMemo(() => resetRequests.filter(r => r.status === 'pending'), [resetRequests]);

  // Available Tabs logic based on role
  const availableTabs = [
    { id: 'feed', label: '📢 التواصل', icon: '📢', visible: true },
    { id: 'lessons', label: '🎨 ركن الإبداع', icon: '🎨', visible: true },
    { id: 'projects', label: '🚀 المشاريع', icon: '🚀', visible: true },
    { id: 'teachers', label: '👥 المعلمات', icon: '👥', visible: isMainSupervisor || (isTempSupervisor && user.tempPermissions?.canViewTeachers) },
    { id: 'team', label: '⚙️ الفريق والأمان', icon: '⚙️', visible: isMainSupervisor } // Only main supervisor sees team settings
  ];

  return (
    <div className="space-y-8 pb-20 animate-fadeIn">
      {/* Reset Result Modal */}
      {resetResult && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[300] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl animate-slideIn text-center border-t-[12px] border-emerald-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-6 shadow-inner">✓</div>
            <h3 className="text-2xl font-black text-slate-900 mb-2">تم التصفير بنجاح</h3>
            <p className="text-slate-500 text-sm font-bold mb-8">المعلمة: <span className="text-slate-900">{resetResult.name}</span></p>

            <div className="bg-slate-50 p-8 rounded-[2rem] border-2 border-dashed border-slate-200 mb-8 relative group">
               <span className="text-[10px] font-black text-slate-400 absolute top-3 right-6 tracking-widest uppercase">كلمة المرور الجديدة</span>
               <div className="text-3xl font-black text-emerald-600 tracking-widest font-mono">{resetResult.pass}</div>
            </div>

            <div className="grid grid-cols-1 gap-4">
              <button 
                onClick={() => copyToClipboard(resetResult.pass)} 
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-sm shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-3 active:scale-95"
              >
                <span className="text-lg">📋</span> نسخ كلمة المرور
              </button>

              {resetResult.phone ? (
                <button 
                  onClick={() => sendToWhatsApp(resetResult.phone!, resetResult.name, resetResult.pass)} 
                  className="w-full bg-[#25D366] text-white py-4 rounded-2xl font-black text-sm shadow-xl hover:opacity-90 transition-all flex items-center justify-center gap-3 active:scale-95"
                >
                  <span className="text-lg">📱</span> إرسال عبر واتساب
                </button>
              ) : (
                <div className="text-[10px] text-amber-500 font-bold bg-amber-50 p-2 rounded-lg">يرجى ملاحظة: رقم الهاتف غير مسجل لإرسال الواتساب تلقائياً</div>
              )}

              <button 
                onClick={() => setResetResult(null)} 
                className="w-full text-slate-400 font-bold text-xs py-2 hover:text-slate-600 transition-colors"
              >
                إغلاق النافذة
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Navigation Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-4xl overflow-x-auto custom-scrollbar">
          {availableTabs.filter(t => t.visible).map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[120px] px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                activeTab === tab.id ? `bg-emerald-600 text-white shadow-lg` : `text-slate-500 hover:bg-emerald-50`
              }`}
            >
              <span>{tab.icon}</span>
              <span>{tab.label}</span>
              {tab.id === 'teachers' && pendingResets.length > 0 && (
                <span className="bg-red-500 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center animate-pulse shadow-sm">!</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'lessons' && (
        <div className="space-y-8 animate-fadeIn">
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <h3 className="text-2xl font-black text-slate-900">ركن الإبداع الدرسي</h3>
              <p className="text-slate-400 font-bold text-sm">متابعة المواد العلمية المرفوعة من المعلمات للعام {academicYear}</p>
              {isTempSupervisor && (
                  <div className="mt-4 flex gap-2 flex-wrap">
                      <span className="text-xs font-bold text-slate-400">تصفح المواد الخاصة بـ:</span>
                      {user.tempPermissions?.allowedSubjects.map(sub => (
                          <span key={sub} className="bg-emerald-50 text-emerald-700 px-3 py-1 rounded-full text-[10px] font-black">{sub}</span>
                      ))}
                      {(!user.tempPermissions?.allowedSubjects || user.tempPermissions.allowedSubjects.length === 0) && (
                          <span className="text-red-400 text-[10px] font-bold">لم يتم تحديد مواد للعرض</span>
                      )}
                  </div>
              )}
           </div>

           <div className="grid grid-cols-1 gap-6">
              {filteredLessons.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-slate-200 font-bold text-slate-300">لا توجد مواد مرفوعة حالياً (أو لا توجد مواد للمواد المصرحة لك)</div>
              ) : (
                filteredLessons.map(material => (
                  <div key={material.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 transition-all hover:shadow-md">
                     <div className="flex justify-between items-start mb-4">
                        <div>
                           <h4 className="text-xl font-black text-slate-900">{material.lessonTitle}</h4>
                           <span className="text-xs font-bold text-emerald-600">بواسطة: {material.teacherName}</span>
                        </div>
                        <span className="text-[10px] text-slate-400 font-bold">{material.createdAt}</span>
                     </div>
                     <p className="text-slate-600 font-bold text-sm mb-6 bg-slate-50 p-5 rounded-2xl border border-slate-100">{material.description}</p>

                     <div className="flex flex-wrap gap-3 mb-8">
                        {material.attachments.map((att, i) => (
                          <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-indigo-50 px-5 py-3 rounded-2xl border border-indigo-100 text-xs font-black text-indigo-700 hover:bg-indigo-100 transition-colors">
                             {getFileIcon(att.type, att.name)} {att.name} <span className="opacity-40 pr-1">📥</span>
                          </a>
                        ))}
                     </div>

                     <div className="border-t border-slate-100 pt-6 space-y-4">
                        <h5 className="font-black text-slate-700 text-sm">سجل النقاش والتوجيه والإثراء:</h5>
                        <div className="space-y-3">
                           {material.comments.map(c => (
                             <div key={c.id} className={`p-5 rounded-[2rem] text-sm ${c.authorRole === UserRole.TEACHER ? 'bg-indigo-50/50 mr-8 border-r-4 border-indigo-400' : 'bg-emerald-50/50 ml-8 border-r-4 border-emerald-400'}`}>
                                <div className="flex justify-between mb-1">
                                   <div className="flex items-center gap-2">
                                      <span className="font-black text-slate-800">{c.authorName}</span>
                                      {c.isEdited && <span className="text-[8px] font-bold text-slate-400 italic">(معدل)</span>}
                                   </div>
                                   <div className="flex items-center gap-2">
                                      <span className="text-[10px] text-slate-400 font-bold">{c.createdAt}</span>
                                      {c.authorId === user.id && (
                                        <button onClick={() => { setEditingCommentId(c.id); setEditCommentText(c.text); }} className="text-slate-300 hover:text-emerald-600 transition-colors">✏️</button>
                                      )}
                                   </div>
                                </div>
                                {editingCommentId === c.id ? (
                                  <div className="space-y-2 mt-2">
                                     <textarea value={editCommentText} onChange={e => setEditCommentText(e.target.value)} className="w-full p-3 border rounded-2xl text-xs font-bold text-slate-900 outline-none focus:border-emerald-500" rows={2} />
                                     <div className="flex gap-2">
                                        <button onClick={() => handleEditComment(material, c.id)} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-[10px] font-black shadow-md">تحديث</button>
                                        <button onClick={() => setEditingCommentId(null)} className="bg-slate-200 text-slate-500 px-4 py-2 rounded-xl text-[10px] font-black">إلغاء</button>
                                     </div>
                                  </div>
                                ) : (
                                  <p className="font-bold text-slate-600 leading-relaxed">{c.text}</p>
                                )}
                             </div>
                           ))}
                        </div>
                        {(!isTempSupervisor || user.tempPermissions?.canComment) && (
                            <div className="flex gap-2 bg-slate-50 p-2 rounded-2xl border border-slate-100 mt-4">
                            <input 
                                type="text" 
                                placeholder="أضف توجيهاً أو تعليقاً للمعلمة..." 
                                value={commentText[material.id] || ''} 
                                onChange={e => setCommentText({...commentText, [material.id]: e.target.value})}
                                className="flex-1 px-5 py-3 rounded-xl bg-white border border-slate-100 font-bold text-sm text-slate-900 outline-none focus:border-emerald-500 transition-all"
                            />
                            <button onClick={() => handleAddComment(material)} className="bg-emerald-600 text-white px-8 py-3 rounded-xl font-black text-xs shadow-lg hover:bg-emerald-700 transition-all active:scale-95">إرسال</button>
                            </div>
                        )}
                     </div>
                  </div>
                ))
              )}
           </div>
        </div>
      )}

      {activeTab === 'teachers' && (
        <div className="space-y-8 animate-fadeIn">
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
             <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                <div>
                  <h3 className="text-2xl font-black text-slate-900">سجل الكادر التعليمي</h3>
                  <p className="text-slate-400 font-bold text-sm">
                      {isTempSupervisor 
                        ? `عرض معلمات المواد: ${user.tempPermissions?.allowedSubjects.join('، ') || 'لا يوجد'}` 
                        : 'إدارة الحسابات وكلمات المرور'}
                  </p>
                </div>
             </div>

              {/* Add Teacher Form - Only if allowed */}
              {(!isTempSupervisor || user.tempPermissions?.canManageUsers) && (
                <div className="mt-8 pt-8 border-t border-slate-100">
                    <h4 className="font-black text-slate-800 mb-6 text-sm flex items-center gap-2">
                      <span className="text-xl">✨</span> تسجيل معلمة جديدة
                    </h4>
                    <div className="bg-slate-50 p-6 rounded-[2.5rem] border border-slate-100 relative overflow-hidden group hover:border-indigo-200 transition-colors shadow-sm">
                        <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-indigo-400 via-purple-400 to-emerald-400"></div>
                        <form onSubmit={handleCreateTeacher} className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-2">
                          <div className="space-y-2">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider mr-2">الاسم الكامل 👤</label>
                              <input 
                                type="text" 
                                placeholder="مثال: سارة محمد أحمد" 
                                value={newTeacherName} 
                                onChange={e => setNewTeacherName(e.target.value)} 
                                className="w-full px-5 py-4 rounded-2xl bg-white border-2 border-slate-100 focus:border-indigo-500 font-bold text-sm text-slate-900 outline-none transition-all focus:shadow-md" 
                              />
                          </div>

                          <div className="space-y-2">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider mr-2">الرقم الوظيفي 🆔</label>
                              <input 
                                type="text" 
                                placeholder="مثال: 901234" 
                                value={newTeacherId} 
                                onChange={e => setNewTeacherId(e.target.value)} 
                                className="w-full px-5 py-4 rounded-2xl bg-white border-2 border-slate-100 focus:border-indigo-500 font-bold text-sm text-slate-900 outline-none transition-all focus:shadow-md" 
                              />
                          </div>

                          <div className="space-y-2">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider mr-2">رقم الهاتف (واتساب) 📱</label>
                              <input 
                                type="text" 
                                placeholder="مثال: 91234567" 
                                value={newTeacherPhone} 
                                onChange={e => setNewTeacherPhone(e.target.value)} 
                                className="w-full px-5 py-4 rounded-2xl bg-white border-2 border-slate-100 focus:border-indigo-500 font-bold text-sm text-slate-900 outline-none transition-all focus:shadow-md" 
                              />
                          </div>

                          <div className="space-y-2">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider mr-2">المادة الدراسية 📚</label>
                              <select 
                                value={newTeacherSubject} 
                                onChange={e => setNewTeacherSubject(e.target.value)} 
                                className="w-full px-5 py-4 rounded-2xl bg-white border-2 border-slate-100 focus:border-indigo-500 font-bold text-sm text-slate-900 outline-none transition-all focus:shadow-md appearance-none"
                              >
                                <option value="لغة عربية">لغة عربية</option>
                                <option value="تربية إسلامية">تربية إسلامية</option>
                                <option value="دراسات اجتماعية">دراسات اجتماعية</option>
                              </select>
                          </div>

                          <div className="space-y-2 md:col-span-2">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider mr-2">الصفوف التي تدرسها 🏫</label>
                              <input 
                                type="text" 
                                placeholder="مثال: 1/2، 2/3، 4/1" 
                                value={newTeacherGrades} 
                                onChange={e => setNewTeacherGrades(e.target.value)} 
                                className="w-full px-5 py-4 rounded-2xl bg-white border-2 border-slate-100 focus:border-indigo-500 font-bold text-sm text-slate-900 outline-none transition-all focus:shadow-md" 
                              />
                          </div>

                          <button 
                            type="submit" 
                            className="md:col-span-2 bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg shadow-indigo-200 text-sm hover:bg-indigo-700 transition-all hover:-translate-y-1 active:scale-95 flex items-center justify-center gap-2"
                          >
                            <span>💾</span> حفظ وإضافة المعلمة للنظام
                          </button>
                        </form>
                    </div>
                </div>
              )}
           </div>

           {pendingResets.length > 0 && (!isTempSupervisor || user.tempPermissions?.canManageUsers) && (
              <div className="bg-white p-8 rounded-[2.5rem] border-2 border-amber-200 shadow-xl shadow-amber-50 space-y-5 animate-pulse-subtle">
                 <h4 className="font-black text-amber-900 flex items-center gap-3 text-lg">
                    <span className="text-2xl">🔔</span> طلبات إعادة تعيين كلمة المرور المعلقة:
                 </h4>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {pendingResets.map(req => (
                       <div key={req.id} className="flex justify-between items-center bg-amber-50 p-6 rounded-[2rem] border border-amber-100 group hover:bg-amber-100 transition-all">
                          <div>
                             <div className="font-black text-slate-800 text-sm mb-1">{req.userName}</div>
                             <div className="text-[10px] text-slate-500 font-bold flex items-center gap-1">🕒 {req.requestedAt}</div>
                          </div>
                          <button 
                            onClick={() => handleResetTeacherAction(req.userId, req.userName)}
                            className="bg-emerald-600 text-white px-6 py-3 rounded-2xl text-[10px] font-black shadow-lg hover:bg-emerald-700 transition-all active:scale-95"
                          >
                             إعادة تعيين الآن
                          </button>
                       </div>
                    ))}
                 </div>
              </div>
           )}

           <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
              <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-right">
                  <thead className="bg-slate-50 border-b border-slate-100 text-slate-500 font-black text-xs">
                    <tr>
                      <th className="p-6">الاسم</th>
                      <th className="p-6">الرقم</th>
                      <th className="p-6">المادة</th>
                      <th className="p-6">الصفوف</th>
                      <th className="p-6 text-center">الإجراءات</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {filteredTeachers.map(teacher => (
                      <tr key={teacher.id} className="hover:bg-slate-50/50 transition-colors group">
                        <td className="p-6 font-black text-slate-800">{teacher.name}</td>
                        <td className="p-6 font-bold text-slate-500 font-mono tracking-wider">{teacher.code}</td>
                        <td className="p-6 font-bold text-emerald-600 text-xs">{teacher.subject || '-'}</td>
                        <td className="p-6 font-bold text-slate-500 text-xs">{teacher.teachingGrades || '-'}</td>
                        <td className="p-6">
                           <div className="flex justify-center gap-3">
                             {(!isTempSupervisor || user.tempPermissions?.canManageUsers) && (
                                <>
                                    <button 
                                        onClick={() => handleResetTeacherAction(teacher.id, teacher.name)} 
                                        className={`px-4 py-2 rounded-xl text-[10px] font-black transition-all flex items-center gap-2 ${pendingResets.find(r => r.userId === teacher.id) ? 'bg-amber-100 text-amber-700 ring-2 ring-amber-400' : 'bg-slate-100 text-slate-600 hover:bg-emerald-50 hover:text-emerald-700'}`}
                                    >
                                        🔑 تصفير
                                    </button>
                                    <button onClick={() => onSoftDeleteTeacher(teacher.id)} className="bg-red-50 text-red-600 px-4 py-2 rounded-xl text-[10px] font-black hover:bg-red-100 transition-colors">
                                        🗑️ أرشفة
                                    </button>
                                </>
                             )}
                             {isTempSupervisor && !user.tempPermissions?.canManageUsers && (
                                 <span className="text-[10px] text-slate-300 font-bold">للعرض فقط</span>
                             )}
                           </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'team' && isMainSupervisor && (
        <div className="space-y-8 max-w-4xl mx-auto animate-fadeIn">
           <div className="bg-white p-10 rounded-[3.5rem] shadow-sm border border-slate-100 space-y-10">
              <div className="text-center">
                 <h3 className="text-2xl font-black text-slate-900 mb-2">إعدادات النظام والأمان</h3>
                 <p className="text-slate-400 text-sm font-bold">التحكم في العام الدراسي وكلمات المرور</p>
              </div>

              {/* Security Passwords Section */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                 <div className="bg-slate-50/50 p-8 rounded-[2.5rem] border border-slate-100 space-y-6">
                    <h4 className="font-black text-slate-800 flex items-center gap-2 text-sm border-b border-slate-200 pb-3">
                       🛡️ كلمة المرور الرئيسية
                    </h4>
                    <div className="space-y-4">
                       <input 
                         type="password" 
                         value={newMainPass} 
                         onChange={e => setNewMainPass(e.target.value)}
                         className="w-full px-5 py-4 rounded-2xl bg-white border border-slate-200 font-black text-center text-slate-900 focus:border-emerald-500 outline-none"
                         placeholder="كلمة المرور الجديدة"
                       />
                       <p className="text-[9px] text-slate-400 font-bold">هذه الكلمة تستخدم للدخول الرسمي للمشرفة الرئيسية.</p>
                    </div>
                 </div>

                 <div className="bg-amber-50/30 p-8 rounded-[2.5rem] border border-amber-100 space-y-6">
                    <h4 className="font-black text-amber-900 flex items-center gap-2 text-sm border-b border-amber-100 pb-3">
                       🔐 كلمة مرور الطوارئ
                    </h4>
                    <div className="space-y-4">
                       <input 
                         type="password" 
                         value={newBackupPass} 
                         onChange={e => setNewBackupPass(e.target.value)}
                         className="w-full px-5 py-4 rounded-2xl bg-white border border-amber-200 font-black text-center text-slate-900 focus:border-amber-500 outline-none"
                         placeholder="تعيين كود الطوارئ"
                       />
                       <p className="text-[9px] text-amber-700/60 font-bold">للاستخدام في حال نسيان الكلمة الرئيسية.</p>
                    </div>
                 </div>
              </div>

              {/* Academic Year Settings */}
              <div className="bg-indigo-50/30 p-8 rounded-[2.5rem] border border-indigo-100 space-y-6">
                <h4 className="font-black text-indigo-900 flex items-center gap-2 text-sm border-b border-indigo-100 pb-3">
                    📅 إعدادات العام الدراسي (التحويل اليدوي)
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                        <label className="text-[10px] font-black text-indigo-400 uppercase tracking-widest block mb-2">السنة الدراسية (نص)</label>
                        <input 
                            type="text" 
                            value={editYear} 
                            onChange={e => setEditYear(e.target.value)}
                            className="w-full px-5 py-4 rounded-2xl bg-white border border-indigo-200 font-black text-center text-slate-900 focus:border-indigo-500 outline-none"
                            placeholder="مثال: 2026-2027"
                        />
                    </div>
                    <div>
                        <label className="text-[10px] font-black text-indigo-400 uppercase tracking-widest block mb-2">الفصل الدراسي (نص)</label>
                        <input 
                            type="text" 
                            value={editSemester} 
                            onChange={e => setEditSemester(e.target.value)}
                            className="w-full px-5 py-4 rounded-2xl bg-white border border-indigo-200 font-black text-center text-slate-900 focus:border-indigo-500 outline-none"
                            placeholder="مثال: الفصل الدراسي الثاني"
                        />
                    </div>
                </div>
                <p className="text-[9px] text-indigo-700/60 font-bold text-center">يتم استخدام هذه النصوص في واجهة النظام والتقارير.</p>
              </div>

              <div className="pt-6">
                 <button 
                   onClick={handleSaveConfig} 
                   className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-lg shadow-2xl hover:bg-emerald-600 transition-all active:scale-95"
                 >
                   حفظ كافة الإعدادات 💾
                 </button>
              </div>
           </div>

           {/* Add Temp Supervisor Section */}
           <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
              <h4 className="font-black text-slate-800 mb-6 flex items-center gap-3">
                 <span>👥</span> إضافة مساعد إشراف (مشرف مؤقت)
              </h4>
              <form onSubmit={handleCreateTempSupervisor} className="space-y-6">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <input type="text" placeholder="اسم المشرف" value={tempName} onChange={e => setTempName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border font-bold text-slate-900" />
                    <input type="text" placeholder="الرقم الوظيفي" value={tempId} onChange={e => setTempId(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border font-bold text-slate-900" />
                 </div>

                 <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
                     <h5 className="font-black text-slate-700 text-sm mb-4">الصلاحيات المسموحة:</h5>

                     <div className="mb-4">
                         <label className="text-xs font-bold text-slate-400 block mb-2">تحديد المواد (للمشاهدة والمتابعة فقط):</label>
                         <div className="flex flex-wrap gap-2">
                             {availableSubjects.map(subject => (
                                 <button
                                    key={subject}
                                    type="button"
                                    onClick={() => toggleSubjectPermission(subject)}
                                    className={`px-4 py-2 rounded-xl text-xs font-black transition-all border ${tempAllowedSubjects.includes(subject) ? 'bg-emerald-600 text-white border-emerald-600' : 'bg-white text-slate-500 border-slate-200'}`}
                                 >
                                     {subject}
                                 </button>
                             ))}
                         </div>
                     </div>

                     <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                         <label className="flex items-center gap-3 bg-white p-3 rounded-xl border border-slate-200 cursor-pointer">
                             <input type="checkbox" checked={tempPermissions.canViewTeachers} onChange={e => setTempPermissions({...tempPermissions, canViewTeachers: e.target.checked})} className="w-5 h-5 accent-emerald-600" />
                             <span className="text-xs font-bold text-slate-700">مشاهدة قائمة المعلمات</span>
                         </label>
                         <label className="flex items-center gap-3 bg-white p-3 rounded-xl border border-slate-200 cursor-pointer">
                             <input type="checkbox" checked={tempPermissions.canComment} onChange={e => setTempPermissions({...tempPermissions, canComment: e.target.checked})} className="w-5 h-5 accent-emerald-600" />
                             <span className="text-xs font-bold text-slate-700">إضافة تعليقات وتوجيهات</span>
                         </label>
                         <label className="flex items-center gap-3 bg-white p-3 rounded-xl border border-slate-200 cursor-pointer">
                             <input type="checkbox" checked={tempPermissions.canApproveProjects} onChange={e => setTempPermissions({...tempPermissions, canApproveProjects: e.target.checked})} className="w-5 h-5 accent-emerald-600" />
                             <span className="text-xs font-bold text-slate-700">اعتماد المشاريع</span>
                         </label>
                         <label className="flex items-center gap-3 bg-white p-3 rounded-xl border border-slate-200 cursor-pointer">
                             <input type="checkbox" checked={tempPermissions.canManageUsers} onChange={e => setTempPermissions({...tempPermissions, canManageUsers: e.target.checked})} className="w-5 h-5 accent-emerald-600" />
                             <span className="text-xs font-bold text-slate-700">إدارة المستخدمين (إضافة/تصفير)</span>
                         </label>
                     </div>
                 </div>

                 <button type="submit" className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg">إضافة المشرف للفريق ➕</button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default SupervisorDashboard;
